import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import { useLanguage } from './LanguageContext';

export interface Achievement {
  id: string;
  titleKey: string;
  descKey: string;
  icon: string;
  category: 'explorer' | 'quiz' | 'collector' | 'designer';
  isUnlocked: boolean;
  progress?: number;
  maxProgress?: number;
}

interface UserStats {
  viewedFlags: string[]; // Array de cca3
  quizzesCompleted: number;
  perfectQuizzes: number;
  maxStreak: number;
  favoritesCount: number;
  flagsDesigned: number;
}

interface AchievementContextType {
  achievements: Achievement[];
  stats: UserStats;
  unlockAchievement: (id: string) => void;
  trackFlagView: (cca3: string) => void;
  trackQuizResult: (score: number, total: number, streak: number) => void;
  trackFavorite: (count: number) => void;
  trackDesign: () => void;
  newUnlocked: Achievement | null;
  clearNewUnlocked: () => void;
}

const INITIAL_STATS: UserStats = {
  viewedFlags: [],
  quizzesCompleted: 0,
  perfectQuizzes: 0,
  maxStreak: 0,
  favoritesCount: 0,
  flagsDesigned: 0,
};

const AchievementContext = createContext<AchievementContextType | undefined>(undefined);

export const AchievementProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { t } = useLanguage();
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('user_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });

  const [unlockedIds, setUnlockedIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('unlocked_achievements');
    return saved ? JSON.parse(saved) : [];
  });

  const [newUnlocked, setNewUnlocked] = useState<Achievement | null>(null);

  useEffect(() => {
    localStorage.setItem('user_stats', JSON.stringify(stats));
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('unlocked_achievements', JSON.stringify(unlockedIds));
  }, [unlockedIds]);

  const achievementsList: Achievement[] = [
    // Explorer Category
    { id: 'first_steps', titleKey: 'achFirstStepsTitle', descKey: 'achFirstStepsDesc', icon: '👣', category: 'explorer', isUnlocked: unlockedIds.includes('first_steps'), progress: stats.viewedFlags.length, maxProgress: 1 },
    { id: 'world_traveler', titleKey: 'achWorldTravelerTitle', descKey: 'achWorldTravelerDesc', icon: '🌍', category: 'explorer', isUnlocked: unlockedIds.includes('world_traveler'), progress: stats.viewedFlags.length, maxProgress: 50 },
    { id: 'vexillology_expert', titleKey: 'achVexExpertTitle', descKey: 'achVexExpertDesc', icon: '🎓', category: 'explorer', isUnlocked: unlockedIds.includes('vexillology_expert'), progress: stats.viewedFlags.length, maxProgress: 150 },

    // Quiz Category
    { id: 'quiz_starter', titleKey: 'achQuizStarterTitle', descKey: 'achQuizStarterDesc', icon: '📝', category: 'quiz', isUnlocked: unlockedIds.includes('quiz_starter'), progress: stats.quizzesCompleted, maxProgress: 1 },
    { id: 'perfect_score', titleKey: 'achPerfectScoreTitle', descKey: 'achPerfectScoreDesc', icon: '✨', category: 'quiz', isUnlocked: unlockedIds.includes('perfect_score'), progress: stats.perfectQuizzes, maxProgress: 1 },
    { id: 'streak_master', titleKey: 'achStreakMasterTitle', descKey: 'achStreakMasterDesc', icon: '🔥', category: 'quiz', isUnlocked: unlockedIds.includes('streak_master'), progress: stats.maxStreak, maxProgress: 10 },

    // Collector Category
    { id: 'curator', titleKey: 'achCuratorTitle', descKey: 'achCuratorDesc', icon: '💖', category: 'collector', isUnlocked: unlockedIds.includes('curator'), progress: stats.favoritesCount, maxProgress: 10 },

    // Designer Category
    { id: 'flag_artist', titleKey: 'achArtistTitle', descKey: 'achArtistDesc', icon: '🎨', category: 'designer', isUnlocked: unlockedIds.includes('flag_artist'), progress: stats.flagsDesigned, maxProgress: 1 },
  ];

  const checkUnlocks = useCallback((updatedStats: UserStats) => {
    const toUnlock: string[] = [];

    if (updatedStats.viewedFlags.length >= 1) toUnlock.push('first_steps');
    if (updatedStats.viewedFlags.length >= 50) toUnlock.push('world_traveler');
    if (updatedStats.viewedFlags.length >= 150) toUnlock.push('vexillology_expert');

    if (updatedStats.quizzesCompleted >= 1) toUnlock.push('quiz_starter');
    if (updatedStats.perfectQuizzes >= 1) toUnlock.push('perfect_score');
    if (updatedStats.maxStreak >= 10) toUnlock.push('streak_master');

    if (updatedStats.favoritesCount >= 10) toUnlock.push('curator');
    if (updatedStats.flagsDesigned >= 1) toUnlock.push('flag_artist');

    toUnlock.forEach(id => {
      if (!unlockedIds.includes(id)) {
        setUnlockedIds(prev => [...prev, id]);
        const found = achievementsList.find(a => a.id === id);
        if (found) setNewUnlocked(found);
      }
    });
  }, [unlockedIds]);

  const trackFlagView = (cca3: string) => {
    setStats(prev => {
      if (prev.viewedFlags.includes(cca3)) return prev;
      const newStats = { ...prev, viewedFlags: [...prev.viewedFlags, cca3] };
      checkUnlocks(newStats);
      return newStats;
    });
  };

  const trackQuizResult = (score: number, total: number, streak: number) => {
    setStats(prev => {
      const newStats = {
        ...prev,
        quizzesCompleted: prev.quizzesCompleted + 1,
        perfectQuizzes: score === total ? prev.perfectQuizzes + 1 : prev.perfectQuizzes,
        maxStreak: Math.max(prev.maxStreak, streak)
      };
      checkUnlocks(newStats);
      return newStats;
    });
  };

  const trackFavorite = (count: number) => {
    setStats(prev => {
      const newStats = { ...prev, favoritesCount: count };
      checkUnlocks(newStats);
      return newStats;
    });
  };

  const trackDesign = () => {
    setStats(prev => {
      const newStats = { ...prev, flagsDesigned: prev.flagsDesigned + 1 };
      checkUnlocks(newStats);
      return newStats;
    });
  };

  const clearNewUnlocked = () => setNewUnlocked(null);

  return (
    <AchievementContext.Provider value={{ 
      achievements: achievementsList, 
      stats, 
      unlockAchievement: (id) => setUnlockedIds(prev => [...prev, id]),
      trackFlagView,
      trackQuizResult,
      trackFavorite,
      trackDesign,
      newUnlocked,
      clearNewUnlocked
    }}>
      {children}
    </AchievementContext.Provider>
  );
};

export const useAchievements = () => {
  const context = useContext(AchievementContext);
  if (!context) throw new Error('useAchievements must be used within AchievementProvider');
  return context;
};

import React, { useEffect, useState } from 'react';
import { useAchievements, Achievement } from '../context/AchievementContext';
import { useLanguage } from '../context/LanguageContext';

const AchievementToast: React.FC = () => {
  const { newUnlocked, clearNewUnlocked } = useAchievements();
  const { t } = useLanguage();
  const [visible, setVisible] = useState(false);
  const [current, setCurrent] = useState<Achievement | null>(null);

  useEffect(() => {
    if (newUnlocked && !visible) {
      setCurrent(newUnlocked);
      setVisible(true);
      const timer = setTimeout(() => {
        setVisible(false);
        setTimeout(clearNewUnlocked, 500);
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [newUnlocked, visible, clearNewUnlocked]);

  if (!current) return null;

  return (
    <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] transition-all duration-500 transform ${visible ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-12 scale-90 pointer-events-none'}`}>
      <div className="bg-white dark:bg-slate-800 border-2 border-amber-400 shadow-2xl rounded-2xl p-4 flex items-center gap-4 min-w-[300px] overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-amber-400 via-yellow-200 to-amber-400 animate-shimmer"></div>
        <div className="text-4xl">{current.icon}</div>
        <div>
          <p className="text-xs font-bold text-amber-600 dark:text-amber-400 uppercase tracking-widest">{t('achievementUnlocked')}</p>
          <h4 className="text-lg font-bold text-slate-900 dark:text-white leading-tight">{t(current.titleKey)}</h4>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t(current.descKey)}</p>
        </div>
      </div>
    </div>
  );
};

export default AchievementToast;

