      // 1. Captura a conquista localmente e LIMPA o contexto global na hora
      setCurrent(newUnlocked);
      clearNewUnlocked();

      // 2. Aciona a animação de entrada (fade-in/slide-up)
      const showTimer = setTimeout(() => {
        setVisible(true);
      }, 100);

      // 3. Define o tempo de permanência: 10 SEGUNDOS (10000ms)
      const hideTimer = setTimeout(() => {
        setVisible(false);

        // 4. Aguarda a animação de saída (500ms) para desmontar o componente
        const cleanupTimer = setTimeout(() => {
          setCurrent(null);
          isAnimating.current = false;
        }, 500);

        return () => clearTimeout(cleanupTimer);
      }, 10000);

      return () => {
        clearTimeout(showTimer);
        clearTimeout(hideTimer);
      };
    }
  }, [newUnlocked, clearNewUnlocked]);

  if (!current) return null;

  return (
    <div 
      className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] transition-all duration-500 transform ease-out
