  viewedFlags: string[];
  quizzesCompleted: number;
  perfectQuizzes: number;
  maxStreak: number;
  favoritesCount: number;
  flagsDesigned: number;
}

interface AchievementContextType {
  achievements: Achievement[];
  stats: UserStats;
  unlockAchievement: (id: string) => void;
  trackFlagView: (cca3: string) => void;
  trackQuizResult: (score: number, total: number, streak: number) => void;
  trackFavorite: (count: number) => void;
  trackDesign: () => void;
  newUnlocked: Achievement | null;
  clearNewUnlocked: () => void;
}

const INITIAL_STATS: UserStats = {
  viewedFlags: [],
  quizzesCompleted: 0,
  perfectQuizzes: 0,
  maxStreak: 0,
  favoritesCount: 0,
  flagsDesigned: 0,
};

const AchievementContext = createContext<AchievementContextType | undefined>(undefined);

export const AchievementProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('user_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });

  const [unlockedIds, setUnlockedIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('unlocked_achievements');
    return saved ? JSON.parse(saved) : [];
  });

  const [newUnlocked, setNewUnlocked] = useState<Achievement | null>(null);

  // Lista base de definições de conquistas
  const achievementsBase = useMemo(() => [
    { id: 'first_steps', titleKey: 'achFirstStepsTitle', descKey: 'achFirstStepsDesc', icon: '👣', category: 'explorer', maxProgress: 1 },
    { id: 'world_traveler', titleKey: 'achWorldTravelerTitle', descKey: 'achWorldTravelerDesc', icon: '🌍', category: 'explorer', maxProgress: 50 },
    { id: 'vexillology_expert', titleKey: 'achVexExpertTitle', descKey: 'achVexExpertDesc', icon: '🎓', category: 'explorer', maxProgress: 150 },
    { id: 'quiz_starter', titleKey: 'achQuizStarterTitle', descKey: 'achQuizStarterDesc', icon: '📝', category: 'quiz', maxProgress: 1 },
    { id: 'perfect_score', titleKey: 'achPerfectScoreTitle', descKey: 'achPerfectScoreDesc', icon: '✨', category: 'quiz', maxProgress: 1 },
    { id: 'streak_master', titleKey: 'achStreakMasterTitle', descKey: 'achStreakMasterDesc', icon: '🔥', category: 'quiz', maxProgress: 10 },
    { id: 'curator', titleKey: 'achCuratorTitle', descKey: 'achCuratorDesc', icon: '💖', category: 'collector', maxProgress: 10 },
    { id: 'flag_artist', titleKey: 'achArtistTitle', descKey: 'achArtistDesc', icon: '🎨', category: 'designer', maxProgress: 1 },
  ], []);

  // Achievements computados com progresso real
  const achievementsList: Achievement[] = useMemo(() => achievementsBase.map(a => ({
    ...a,
    isUnlocked: unlockedIds.includes(a.id),
    progress: a.id === 'curator' ? stats.favoritesCount :
              a.id === 'flag_artist' ? stats.flagsDesigned :
              a.id === 'quiz_starter' ? stats.quizzesCompleted :
              a.id === 'perfect_score' ? stats.perfectQuizzes :
              a.id === 'streak_master' ? stats.maxStreak :
              a.id.includes('explorer') || a.id === 'first_steps' || a.id === 'world_traveler' || a.id === 'vexillology_expert' ? stats.viewedFlags.length : 0
  })), [achievementsBase, unlockedIds, stats]);

  // Salvar no localStorage
  useEffect(() => {
    localStorage.setItem('user_stats', JSON.stringify(stats));
    localStorage.setItem('unlocked_achievements', JSON.stringify(unlockedIds));
  }, [stats, unlockedIds]);

  // Verificar desbloqueios sempre que os stats mudarem
  useEffect(() => {
    const toUnlock: string[] = [];

    if (stats.viewedFlags.length >= 1) toUnlock.push('first_steps');
    if (stats.viewedFlags.length >= 50) toUnlock.push('world_traveler');
    if (stats.viewedFlags.length >= 150) toUnlock.push('vexillology_expert');
    if (stats.quizzesCompleted >= 1) toUnlock.push('quiz_starter');
    if (stats.perfectQuizzes >= 1) toUnlock.push('perfect_score');
    if (stats.maxStreak >= 10) toUnlock.push('streak_master');
    if (stats.favoritesCount >= 10) toUnlock.push('curator');
    if (stats.flagsDesigned >= 1) toUnlock.push('flag_artist');

    const newlyUnlockedId = toUnlock.find(id => !unlockedIds.includes(id));

    if (newlyUnlockedId) {
      setUnlockedIds(prev => [...prev, newlyUnlockedId]);
      const ach = achievementsBase.find(a => a.id === newlyUnlockedId);
      if (ach) {
        setNewUnlocked({ ...ach, isUnlocked: true });
      }
    }
  }, [stats, unlockedIds, achievementsBase]);

  const trackFlagView = useCallback((cca3: string) => {
    setStats(prev => {
      if (prev.viewedFlags.includes(cca3)) return prev;
      return { ...prev, viewedFlags: [...prev.viewedFlags, cca3] };
    });
  }, []);

  const trackQuizResult = useCallback((score: number, total: number, streak: number) => {
    setStats(prev => ({
      ...prev,
      quizzesCompleted: prev.quizzesCompleted + 1,
      perfectQuizzes: score === total ? prev.perfectQuizzes + 1 : prev.perfectQuizzes,
      maxStreak: Math.max(prev.maxStreak, streak)
    }));
  }, []);

  const trackFavorite = useCallback((count: number) => {
    setStats(prev => (prev.favoritesCount === count ? prev : { ...prev, favoritesCount: count }));
  }, []);

  const trackDesign = useCallback(() => {
    setStats(prev => ({ ...prev, flagsDesigned: prev.flagsDesigned + 1 }));
  }, []);

  const clearNewUnlocked = useCallback(() => setNewUnlocked(null), []);
  const unlockAchievement = useCallback((id: string) => setUnlockedIds(prev => prev.includes(id) ? prev : [...prev, id]), []);

  return (
    <AchievementContext.Provider value={{ 
      achievements: achievementsList, 
      stats, 
      unlockAchievement,
      trackFlagView,
      trackQuizResult,
      trackFavorite,
      trackDesign,
      newUnlocked,
      clearNewUnlocked
    }}>
      {children}
    </AchievementContext.Provider>
  );
};

export const useAchievements = () => {
  const context = useContext(AchievementContext);
  if (!context) throw new Error('useAchievements must be used within AchievementProvider');
  return context;
};

