const AchievementToast: React.FC = () => {
  const { newUnlocked, clearNewUnlocked } = useAchievements();
  const { t } = useLanguage();
  const [visible, setVisible] = useState(false);
  const [current, setCurrent] = useState<Achievement | null>(null);
  const animationRef = useRef<boolean>(false);

  useEffect(() => {
    // Se temos uma conquista pendente e não estamos mostrando nada no momento
    if (newUnlocked && !animationRef.current) {
      animationRef.current = true;

      // Capturamos localmente a conquista
      const toastAchievement = { ...newUnlocked };
      setCurrent(toastAchievement);

      // Limpamos o estado global IMEDIATAMENTE para não disparar em loop
      clearNewUnlocked();

      // Inicia sequência de animação
      // 1. Entrada
      const enterTimeout = setTimeout(() => {
        setVisible(true);
      }, 100);

      // 2. Tempo de espera (10 segundos)
      const exitTimeout = setTimeout(() => {
        setVisible(false);

        // 3. Limpeza final após transição CSS (500ms)
        const cleanupTimeout = setTimeout(() => {
          setCurrent(null);
          animationRef.current = false;
        }, 500);

        return () => clearTimeout(cleanupTimeout);
      }, 10000);

      return () => {
        clearTimeout(enterTimeout);
        clearTimeout(exitTimeout);
      };
    }
  }, [newUnlocked, clearNewUnlocked]);

  if (!current) return null;

  return (
    <div 
      className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] transition-all duration-700 transform ease-out
        ${visible ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-12 scale-90 pointer-events-none'}`}
    >
      <div className="bg-white dark:bg-slate-800 border-2 border-amber-400 shadow-[0_20px_50px_rgba(0,0,0,0.3)] dark:shadow-[0_20px_50px_rgba(0,0,0,0.5)] rounded-2xl p-4 flex items-center gap-4 min-w-[320px] max-w-[90vw] overflow-hidden relative">
        {/* Barra de progresso visual de 10 segundos */}
        <div 
          className="absolute top-0 left-0 h-1 bg-amber-400 transition-all duration-[10000ms] ease-linear"
          style={{ width: visible ? '100%' : '0%' }}
        ></div>

        <div className="text-4xl flex-shrink-0 animate-bounce">{current.icon}</div>
        <div className="flex-grow min-w-0">
          <p className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest truncate">
            {t('achievementUnlocked')}
          </p>
          <h4 className="text-base font-bold text-slate-900 dark:text-white leading-tight truncate">
            {t(current.titleKey)}
          </h4>
          <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2">
            {t(current.descKey)}
