import type { Country } from '../types';
import { API_BASE_URL, API_FIELDS } from '../constants';

const API_URL = `${API_BASE_URL}?fields=${API_FIELDS.join(',')}`;

const CACHE_KEY = 'countriesData_v2';
const CACHE_EXPIRATION_MS = 24 * 60 * 60 * 1000; // 24 horas

export const fetchCountries = async (): Promise<Country[]> => {
    // 1. Tentar obter do cache primeiro (mesmo que expirado, como fallback de segurança)
    const cachedItem = localStorage.getItem(CACHE_KEY);
    let cachedData: Country[] | null = null;
    let isExpired = true;

    if (cachedItem) {
        try {
            const { timestamp, data } = JSON.parse(cachedItem);
            cachedData = data;
            isExpired = Date.now() - timestamp > CACHE_EXPIRATION_MS;

            // Se não expirou, retorna imediatamente
            if (!isExpired && data && data.length > 0) {
                return data;
            }
        } catch (error) {
            console.error("Error parsing cached country data", error);
            localStorage.removeItem(CACHE_KEY);
        }
    }

    // 2. Tentar buscar da API
    try {
        const response = await fetch(API_URL);
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data: Country[] = await response.json();

        if (data && data.length > 0) {
            // Atualizar cache
            try {
                const cachePayload = {
                    timestamp: Date.now(),
                    data: data,
                };
                localStorage.setItem(CACHE_KEY, JSON.stringify(cachePayload));
            } catch (error) {
                console.error("Failed to update cache", error);
            }
            return data;
        }
    } catch (error) {
        console.error("Fetch failed, attempting to use expired cache as fallback", error);

        // 3. Fallback: Se a API falhou mas temos dados em cache (mesmo que expirados), use-os
        if (cachedData && cachedData.length > 0) {
            return cachedData;
        }

        // Se não tem cache nem API, propaga o erro para a UI
        throw new Error('Não foi possível carregar os dados das bandeiras. Verifique sua conexão.');
    }

    return [];
};

const CACHE_NAME = 'flag-explorer-cache-v2';
const APP_SHELL_URLS = [
  '/',
  '/index.html',
];

const DYNAMIC_CACHE_PATTERNS = [
  'https://restcountries.com/v3.1/all',
  'https://aistudiocdn.com/',
  'https://cdn.jsdelivr.net/'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(APP_SHELL_URLS);
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  return self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Estratégia Stale-While-Revalidate para recursos externos
  if (DYNAMIC_CACHE_PATTERNS.some(pattern => url.href.startsWith(pattern))) {
    event.respondWith(
      caches.open(CACHE_NAME).then((cache) => {
        return cache.match(event.request).then((cachedResponse) => {
          const fetchPromise = fetch(event.request).then((networkResponse) => {
            if (networkResponse && networkResponse.status === 200) {
              cache.put(event.request, networkResponse.clone());
            }
            return networkResponse;
          }).catch(err => {
            // Se falhar e não houver cache, retorna um erro amigável ou deixa falhar para o app tratar
            if (!cachedResponse) throw err;
            return cachedResponse;
          });
          return cachedResponse || fetchPromise;
        });
      })
    );
    return;
  }

  // Estratégia Network-First com fallback para cache para o resto do app
  event.respondWith(
    fetch(event.request)
      .then((networkResponse) => {
        if (networkResponse && networkResponse.status === 200 && event.request.method === 'GET') {
           const responseClone = networkResponse.clone();
           caches.open(CACHE_NAME).then(cache => cache.put(event.request, responseClone));
        }
        return networkResponse;
      })
      .catch(() => {
        return caches.match(event.request);
      })
  );
});

