            >
                <span className="truncate">{t('sortBy')}: {currentLabel}</span>
                <svg className={`w-5 h-5 ml-2 -mr-1 transition-transform duration-200 ${isOpen ? 'transform rotate-180' : ''}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
            </button>
            {isOpen && (
                <div className="absolute right-0 mt-2 w-56 rounded-md shadow-lg bg-white dark:bg-slate-800 ring-1 ring-black ring-opacity-5 dark:ring-slate-700 z-10 animate-fade-in-up-short">
                    <div className="py-1" role="listbox" aria-orientation="vertical">
                        {sortOptions.map(option => (
                            <button
                                key={option.key}
                                onClick={() => {
                                    setSortOrder(option.key);
                                    setIsOpen(false);
                                }}
                                className="block w-full text-left px-4 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700"
                                role="option"
                                aria-selected={sortOrder === option.key}
                            >
                                {option.label}
                            </button>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

interface ExplorerContentProps {
    countries: Country[];
    filteredCountries: Country[];
    isLoading: boolean;
    error: string | null;
    flagOfTheDay: FlagOfTheDayData | null;
    isFlagOfTheDayLoading: boolean;
    handleCardClick: (country: Country) => void;
    favorites: Set<string>;
    onToggleFavorite: (country: Country) => void;
    selectedContinent: string;
    setSelectedContinent: (continent: string) => void;
    searchQuery: string;
    setSearchQuery: (query: string) => void;
    isCompareModeActive: boolean;
    handleToggleCompareMode: () => void;
    sortOrder: SortOrder;
    setSortOrder: (order: SortOrder) => void;
    comparisonList: Country[];
    onRetry?: () => void;
}

const ExplorerContent: React.FC<ExplorerContentProps> = ({
    filteredCountries,
    isLoading,
    error,
    flagOfTheDay,
    isFlagOfTheDayLoading,
    handleCardClick,
    favorites,
    onToggleFavorite,
    selectedContinent,
    setSelectedContinent,
    searchQuery,
    setSearchQuery,
    isCompareModeActive,
    handleToggleCompareMode,
    sortOrder,
    setSortOrder,
    comparisonList,
    onRetry
}) => {
    const { t } = useLanguage();

    return (
        <>
            <Hero 
                flagOfTheDay={flagOfTheDay} 
                isLoading={isFlagOfTheDayLoading}
                onFlagClick={handleCardClick}
            />

            <div className="grid grid-cols-1 md:grid-cols-4 gap-8 mt-12">
                <aside className="md:col-span-1">
                    <div className="md:sticky top-24">
                       <FilterNavigator
                            continents={CONTINENTS_API_VALUES}
                            selectedContinent={selectedContinent}
                            setSelectedContinent={setSelectedContinent}
                            searchQuery={searchQuery}
                            onSearchChange={setSearchQuery}
                            isCompareModeActive={isCompareModeActive}
                            onToggleCompareMode={handleToggleCompareMode}
                       />
                    </div>
                </aside>
                <main className="md:col-span-3">
                    {isCompareModeActive && <CompareModeIndicator onDisable={handleToggleCompareMode} />}

                    <div className="flex justify-end mb-6">
                        <SortControl sortOrder={sortOrder} setSortOrder={setSortOrder} />
                    </div>

                    {isLoading ? (
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {Array.from({ length: 12 }).map((_, index) => <SkeletonCard key={index} />)}
                        </div>
                    ) : error ? (
                        <div className="col-span-full text-center py-16 bg-red-50 dark:bg-red-900/10 rounded-2xl border-2 border-red-100 dark:border-red-900/30">
                            <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-16 w-16 text-red-400 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                            </svg>
                            <h3 className="text-xl font-bold text-red-800 dark:text-red-300">{t('errorOops')}</h3>
                            <p className="text-red-600 dark:text-red-400 mt-2 mb-6 max-w-md mx-auto">{error}</p>
                            <button 
                                onClick={onRetry}
                                className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-full shadow-sm text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition-colors"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2" viewBox="0 0 20 20" fill="currentColor">
                                    <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 110 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" />
                                </svg>
                                {t('playAgain') || 'Tentar Novamente'}
                            </button>
                        </div>
                    ) : filteredCountries.length > 0 ? (
                        <VirtualFlagGrid
                            countries={filteredCountries}
                            onCardClick={handleCardClick}
                            isCompareModeActive={isCompareModeActive}
                            comparisonList={comparisonList}
                            favorites={favorites}
                            onToggleFavorite={onToggleFavorite}
                        />
                    ) : (
                        <div className="col-span-full">
                            {selectedContinent === 'Favorites' ? (
                                <div className="text-center py-12 bg-gray-50 dark:bg-slate-800/50 rounded-lg">
                                    <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                                    </svg>
                                    <h3 className="mt-2 text-lg font-medium text-gray-900 dark:text-slate-200">{t('noFavorites')}</h3>
                                    <p className="mt-1 text-sm text-gray-500 dark:text-slate-400">{t('noFavoritesDescription')}</p>
                                </div>
                            ) : (
                                 <NoResults />
                            )}
                        </div>
                    )}
                </main>
            </div>
        </>
    );
};

const UNIQUE_FLAG_CCAS = [
    'NPL', 'CHE', 'VAT', 'PRY', 'DNK', 'PHL', 'MOZ', 'QAT', // Original
    'BLZ', 'CYP', 'BRA', 'AUT', 'LSO', 'KHM', 'TKM', 'LKA', // New
    'CAN', 'ZAF', 'DOM', 'JAM', 'NOR', 'UGA',               // New
    'BTN', 'LBY', 'SAU', 'KIR', 'DMA', 'SWZ'                // More new flags
];

const AppContent: React.FC = () => {
    const { t, language } = useLanguage();
    const { trackFlagView, trackFavorite } = useAchievements();
    const [countries, setCountries] = useState<Country[]>([]);
    const [searchQuery, setSearchQuery] = useState<string>('');
    const debouncedSearchQuery = useDebounce(searchQuery, 300);
    const [selectedContinent, setSelectedContinent] = useState<string>('All');
    const [isLoading, setIsLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);
    const [selectedCountry, setSelectedCountry] = useState<Country | null>(null);
    const [view, setView] = useState<View>('explorer');
    const [sortOrder, setSortOrder] = useState<SortOrder>('name_asc');

    const [collectionsData, setCollectionsData] = useState<CollectionData[] | null>(null);
    const [isCollectionsLoading, setIsCollectionsLoading] = useState<boolean>(false);
    const [flagOfTheDay, setFlagOfTheDay] = useState<FlagOfTheDayData | null>(null);
    const [isFlagOfTheDayLoading, setIsFlagOfTheDayLoading] = useState<boolean>(true);

    const [uniqueFlagOfTheDay, setUniqueFlagOfTheDay] = useState<UniqueFlagOfTheDayData | null>(null);
    const [isUniqueFlagOfTheDayLoading, setIsUniqueFlagOfTheDayLoading] = useState<boolean>(true);

    const [isCompareModeActive, setIsCompareModeActive] = useState(false);
    const [comparisonList, setComparisonList] = useState<Country[]>([]);
    const [isCompareModalOpen, setIsCompareModalOpen] = useState(false);

    const [favorites, setFavorites] = useState<Set<string>>(() => {
        try {
            const savedFavorites = localStorage.getItem('favorites');
            return new Set(savedFavorites ? JSON.parse(savedFavorites) : []);
        } catch {
            return new Set();
        }
    });

    const [toastInfo, setToastInfo] = useState<{ message: string; type: 'add' | 'remove' } | null>(null);
    const [isToastVisible, setIsToastVisible] = useState<boolean>(false);
    const toastTimerRef = useRef<number | null>(null);

    const [scrollProgress, setScrollProgress] = useState(0);

    const showToast = useCallback((message: string, type: 'add' | 'remove') => {
        if (toastTimerRef.current) {
            clearTimeout(toastTimerRef.current);
        }
        setToastInfo({ message, type });
        setIsToastVisible(true);
        toastTimerRef.current = window.setTimeout(() => {
            setIsToastVisible(false);
        }, 3000);
    }, []);

    useEffect(() => {
        localStorage.setItem('favorites', JSON.stringify(Array.from(favorites)));
        trackFavorite(favorites.size);
    }, [favorites, trackFavorite]);

    const handleToggleFavorite = useCallback((country: Country) => {
        const countryName = language === 'pt' ? country.translations.por.common : country.name.common;
        setFavorites(prevFavorites => {
            const newFavorites = new Set(prevFavorites);
            if (newFavorites.has(country.cca3)) {
                newFavorites.delete(country.cca3);
                showToast(t('removedFromFavoritesToast', { countryName }), 'remove');
            } else {
                newFavorites.add(country.cca3);
                showToast(t('addedToFavoritesToast', { countryName }), 'add');
            }
            return newFavorites;
        });
    }, [language, showToast, t]);

    useEffect(() => {
        const handleFocusIn = (e: Event) => {
            if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
                document.body.classList.add('keyboard-visible');
            }
        };

        const handleFocusOut = (e: Event) => {
            if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
                setTimeout(() => {
                    const activeEl = document.activeElement;
                    if (!(activeEl instanceof HTMLInputElement || activeEl instanceof HTMLTextAreaElement)) {
                        document.body.classList.remove('keyboard-visible');
                    }
                }, 50);
            }
        };

        const handleScroll = () => {
            const totalScroll = document.documentElement.scrollTop;
            const windowHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
            const scroll = `${(totalScroll / windowHeight) * 100}`;
            setScrollProgress(Number(scroll));
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        document.addEventListener('focusin', handleFocusIn);
        document.addEventListener('focusout', handleFocusOut);

        return () => {
            window.removeEventListener('scroll', handleScroll);
            document.removeEventListener('focusin', handleFocusIn);
            document.removeEventListener('focusout', handleFocusOut);
        };
    }, []);

    const fetchCollections = useCallback(async (countryData: Country[]) => {
        setIsCollectionsLoading(true);
        try {
            const collections = fetchAllCollections(countryData, language);
            setCollectionsData(collections);
        } catch (error) {
            console.error("Failed to fetch collections:", error);
        } finally {
            setIsCollectionsLoading(false);
        }
    }, [language]);

    const manageFlagOfTheDay = useCallback((countryData: Country[]) => {
        if (countryData.length === 0) {
            setIsFlagOfTheDayLoading(false);
            return;
        }

        const now = new Date();
        const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
        const countryForToday = getDeterministicCountryForDate(today, countryData);
        if (!countryForToday) return;

        const storageKey = `flagOfTheDay_v3_${language}`;
        const storedFlagRaw = localStorage.getItem(storageKey);
        if (storedFlagRaw) {
            try {
                const storedFlag: StoredFlagOfTheDay = JSON.parse(storedFlagRaw);
                if (storedFlag.date === today && storedFlag.country.cca3 === countryForToday.cca3) {
                    setFlagOfTheDay({ country: storedFlag.country, title: storedFlag.title });
                    setIsFlagOfTheDayLoading(false);
                    return;
                }
            } catch (e) {
                console.error("Corrupted flag of the day in cache, removing it.", e);
                localStorage.removeItem(storageKey);
            }
        }

        const curatedTitle = FLAG_OF_THE_DAY_TITLES[countryForToday.cca3]?.[language];
        const fallbackTitle = language === 'pt' ? countryForToday.translations.por.common : countryForToday.name.common;
        const title = curatedTitle || fallbackTitle;

        const flagDayData = { country: countryForToday, title };
        setFlagOfTheDay(flagDayData);

        try {
            const newStoredFlag: StoredFlagOfTheDay = { date: today, ...flagDayData };
            localStorage.setItem(storageKey, JSON.stringify(newStoredFlag));
        } catch (error) {
            console.error("Failed to cache flag of the day data.", error);
        }

        setIsFlagOfTheDayLoading(false);

    }, [language]);

    const manageUniqueFlagOfTheDay = useCallback((countryData: Country[]) => {
        if (countryData.length === 0) {
            setIsUniqueFlagOfTheDayLoading(false);
            return;
        }

        const uniqueCountries = countryData.filter(c => UNIQUE_FLAG_CCAS.includes(c.cca3));
        if (uniqueCountries.length === 0) {
            setIsUniqueFlagOfTheDayLoading(false);
            return;
        }

        const now = new Date();
        const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

        const countryForToday = getDeterministicCountryForDate(today, uniqueCountries);
        if (!countryForToday) return;

        const storageKey = `uniqueFlagOfTheDay_${language}`;
        const storedFlagRaw = localStorage.getItem(storageKey);
        if (storedFlagRaw) {
            try {
                const storedFlag: StoredUniqueFlagOfTheDay = JSON.parse(storedFlagRaw);
                if (storedFlag.date === today && storedFlag.country.cca3 === countryForToday.cca3) {
                    setUniqueFlagOfTheDay({ country: storedFlag.country, descriptionKey: storedFlag.descriptionKey });
                    setIsUniqueFlagOfTheDayLoading(false);
                    return;
                }
            } catch (e) {
                localStorage.removeItem(storageKey);
            }
        }

        const descriptionKeyMap: { [key: string]: UniqueFlagDescriptionKey } = {
            'NPL': 'nepalFlagDesc',
            'CHE': 'switzerlandFlagDesc',
            'VAT': 'vaticanFlagDesc',
            'PRY': 'paraguayFlagDesc',
            'DNK': 'denmarkFlagDesc',
            'PHL': 'philippinesFlagDesc',
            'MOZ': 'mozambiqueFlagDesc',
            'QAT': 'qatarFlagDesc',
            'BLZ': 'belizeFlagDesc',
            'CYP': 'cyprusFlagDesc',
            'BRA': 'brazilFlagDesc',
            'AUT': 'austriaFlagDesc',
            'LSO': 'lesothoFlagDesc',
            'KHM': 'cambodiaFlagDesc',
            'TKM': 'turkmenistanFlagDesc',
            'LKA': 'sriLankaFlagDesc',
            'CAN': 'canadaFlagDesc',
            'ZAF': 'southAfricaFlagDesc',
            'DOM': 'dominicanRepublicFlagDesc',
            'JAM': 'jamaicaFlagDesc',
            'NOR': 'norwayFlagDesc',
            'UGA': 'ugandaFlagDesc',
            'BTN': 'bhutanFlagDesc',
            'LBY': 'libyaFlagDesc',
            'SAU': 'saudiArabiaFlagDesc',
            'KIR': 'kiribatiFlagDesc',
            'DMA': 'dominicaFlagDesc',
            'SWZ': 'eswatiniFlagDesc',
        };
        const descriptionKey = descriptionKeyMap[countryForToday.cca3];

        const uniqueFlagData = { country: countryForToday, descriptionKey };
        setUniqueFlagOfTheDay(uniqueFlagData);

        try {
            const newStoredFlag: StoredUniqueFlagOfTheDay = { date: today, ...uniqueFlagData };
            localStorage.setItem(storageKey, JSON.stringify(newStoredFlag));
        } catch (error) {
            console.error("Failed to cache unique flag of the day data.", error);
        }

        setIsUniqueFlagOfTheDayLoading(false);

    }, [language]);

    const loadData = useCallback(async () => {
        try {
            setIsLoading(true);
            setError(null);
            const unsortedData = await fetchCountries();
            const data = [...unsortedData].sort((a, b) => a.cca3.localeCompare(b.cca3));
            setCountries(data);
            fetchCollections(data);
            manageFlagOfTheDay(data);
            manageUniqueFlagOfTheDay(data);
        } catch (err: any) {
            setError(err.message || t('fetchError'));
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    }, [t, fetchCollections, manageFlagOfTheDay, manageUniqueFlagOfTheDay]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const handleCardClick = (country: Country) => {
        if (isCompareModeActive) {
            setComparisonList(prev => {
                const isAlreadySelected = prev.some(c => c.cca3 === country.cca3);
                if (isAlreadySelected) {
                    return prev.filter(c => c.cca3 !== country.cca3);
                }
                if (prev.length < 2) {
                    return [...prev, country];
                }
                return prev;
            });
        } else {
            setSelectedCountry(country);
            trackFlagView(country.cca3);
        }
    };

    const handleCloseModal = () => {
        setSelectedCountry(null);
    };

    const handleClearComparison = () => setComparisonList([]);
    const handleOpenCompareModal = () => setIsCompareModalOpen(true);
    const handleCloseCompareModal = () => setIsCompareModalOpen(false);

    const handleToggleCompareMode = useCallback(() => {
        setIsCompareModeActive(prev => {
            const nextState = !prev;
            if (!nextState) {
                setComparisonList([]);
            }
            return nextState;
        });
    }, []);

    const filteredCountries = useMemo(() => {
        let result = [...countries];

        if (selectedContinent !== 'All') {
            if (selectedContinent === 'Favorites') {
                result = result.filter(country => favorites.has(country.cca3));
            } else {
                result = result.filter(country => country.continents.includes(selectedContinent));
            }
        }

        if (debouncedSearchQuery.trim()) {
            const lowerCaseQuery = debouncedSearchQuery.toLowerCase();
            result = result.filter(country => {
                 const commonName = language === 'pt' ? country.translations.por.common : country.name.common;
                 const officialName = language === 'pt' ? country.translations.por.official : country.name.official;
                 return commonName.toLowerCase().includes(lowerCaseQuery) ||
                        officialName.toLowerCase().includes(lowerCaseQuery) ||
                        country.cca3.toLowerCase().includes(lowerCaseQuery);
            });
        }

        return [...result].sort((a, b) => {
            const nameA = language === 'pt' ? a.translations.por.common : a.name.common;
            const nameB = language === 'pt' ? b.translations.por.common : b.name.common;

            switch (sortOrder) {
                case 'name_desc':
                    return nameB.localeCompare(nameA);
                case 'pop_desc':
                    return b.population - a.population;
                case 'pop_asc':
                    return a.population - b.population;
                case 'area_desc':
                    return b.area - a.area;
                case 'area_asc':
                    return a.area - b.area;
                case 'name_asc':
                default:
                    return nameA.localeCompare(nameB);
            }
        });
    }, [countries, selectedContinent, language, debouncedSearchQuery, favorites, sortOrder]);

    const renderContent = () => {
        switch (view) {
            case 'explorer':
                return (
                    <ExplorerContent
                        countries={countries}
                        filteredCountries={filteredCountries}
                        isLoading={isLoading}
                        error={error}
                        flagOfTheDay={flagOfTheDay}
                        isFlagOfTheDayLoading={isFlagOfTheDayLoading}
                        handleCardClick={handleCardClick}
                        favorites={favorites}
                        onToggleFavorite={handleToggleFavorite}
                        selectedContinent={selectedContinent}
                        setSelectedContinent={setSelectedContinent}
                        searchQuery={searchQuery}
                        setSearchQuery={setSearchQuery}
                        isCompareModeActive={isCompareModeActive}
                        handleToggleCompareMode={handleToggleCompareMode}
                        sortOrder={sortOrder}
                        setSortOrder={setSortOrder}
                        comparisonList={comparisonList}
                        onRetry={loadData}
                    />
                );
            case 'quiz':
                return <QuizView countries={countries} onBackToExplorer={() => setView('explorer')} />;
            case 'discover':
                return <DiscoverView 
                    countries={countries}
                    collections={collectionsData}
                    isLoading={isCollectionsLoading}
                    onCardClick={handleCardClick}
                    favorites={favorites}
                    onToggleFavorite={handleToggleFavorite}
                    uniqueFlagOfTheDay={uniqueFlagOfTheDay}
                    isUniqueFlagOfTheDayLoading={isUniqueFlagOfTheDayLoading}
                />;
            case 'designer':
                return <DesignerView />;
            default:
                return null;
        }
    }

    return (
        <div className="min-h-screen flex flex-col">
            <Header currentView={view} setView={setView} scrollProgress={scrollProgress} />
            <main className="flex-grow pt-20">
                 <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-8">
                     <Suspense fallback={<PageLoader />}>
                        {renderContent()}
                    </Suspense>
                 </div>
            </main>
            <Suspense fallback={null}>
                {selectedCountry && (
                    <FlagModal 
                        country={selectedCountry}
                        onClose={handleCloseModal}
                        isFavorite={favorites.has(selectedCountry.cca3)}
                        onToggleFavorite={handleToggleFavorite}
                    />
                )}
                {isCompareModalOpen && comparisonList.length === 2 && (
                     <CompareModal 
                        countries={[comparisonList[0], comparisonList[1]]}
                        onClose={handleCloseCompareModal}
                    />
                )}
            </Suspense>
            <Footer />
            <ScrollToTopButton />
            {view === 'explorer' && isCompareModeActive && (
                <CompareTray 
                    comparisonList={comparisonList}
                    onCompare={handleOpenCompareModal}
                    onClear={handleClearComparison}
                />
            )}
            {!(view === 'explorer' && isCompareModeActive) && <BottomNav currentView={view} setView={setView} />}
            <Toast info={toastInfo} isVisible={isToastVisible} />
            <AchievementToast />
        </div>
    );
};

const App: React.FC = () => (
    <AchievementProvider>
        <AppContent />
    </AchievementProvider>
);

export default App;

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback, useMemo, useRef } from 'react';
import { useLanguage } from './LanguageContext';

export interface Achievement {
  id: string;
  titleKey: string;
  descKey: string;
  icon: string;
  category: 'explorer' | 'quiz' | 'collector' | 'designer';
  isUnlocked: boolean;
  progress?: number;
  maxProgress?: number;
}

interface UserStats {
  viewedFlags: string[];
  quizzesCompleted: number;
  perfectQuizzes: number;
  maxStreak: number;
  favoritesCount: number;
  flagsDesigned: number;
}

interface AchievementContextType {
  achievements: Achievement[];
  stats: UserStats;
  unlockAchievement: (id: string) => void;
  trackFlagView: (cca3: string) => void;
  trackQuizResult: (score: number, total: number, streak: number) => void;
  trackFavorite: (count: number) => void;
  trackDesign: () => void;
  notificationQueue: Achievement[];
  popNotification: () => void;
}

const INITIAL_STATS: UserStats = {
  viewedFlags: [],
  quizzesCompleted: 0,
  perfectQuizzes: 0,
  maxStreak: 0,
  favoritesCount: 0,
  flagsDesigned: 0,
};

const AchievementContext = createContext<AchievementContextType | undefined>(undefined);

export const AchievementProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('user_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });

  const [unlockedIds, setUnlockedIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('unlocked_achievements');
    return saved ? JSON.parse(saved) : [];
  });

  const [notificationQueue, setNotificationQueue] = useState<Achievement[]>([]);

  // Lista base de definições de conquistas
  const achievementsBase = useMemo(() => [
    { id: 'first_steps', titleKey: 'achFirstStepsTitle', descKey: 'achFirstStepsDesc', icon: '👣', category: 'explorer', maxProgress: 1 },
    { id: 'world_traveler', titleKey: 'achWorldTravelerTitle', descKey: 'achWorldTravelerDesc', icon: '🌍', category: 'explorer', maxProgress: 50 },
    { id: 'vexillology_expert', titleKey: 'achVexExpertTitle', descKey: 'achVexExpertDesc', icon: '🎓', category: 'explorer', maxProgress: 150 },
    { id: 'quiz_starter', titleKey: 'achQuizStarterTitle', descKey: 'achQuizStarterDesc', icon: '📝', category: 'quiz', maxProgress: 1 },
    { id: 'perfect_score', titleKey: 'achPerfectScoreTitle', descKey: 'achPerfectScoreDesc', icon: '✨', category: 'quiz', maxProgress: 1 },
    { id: 'streak_master', titleKey: 'achStreakMasterTitle', descKey: 'achStreakMasterDesc', icon: '🔥', category: 'quiz', maxProgress: 10 },
    { id: 'curator', titleKey: 'achCuratorTitle', descKey: 'achCuratorDesc', icon: '💖', category: 'collector', maxProgress: 10 },
    { id: 'flag_artist', titleKey: 'achArtistTitle', descKey: 'achArtistDesc', icon: '🎨', category: 'designer', maxProgress: 1 },
  ], []);

  const achievementsList: Achievement[] = useMemo(() => achievementsBase.map(a => ({
    ...a,
    isUnlocked: unlockedIds.includes(a.id),
    progress: a.id === 'curator' ? stats.favoritesCount :
              a.id === 'flag_artist' ? stats.flagsDesigned :
              a.id === 'quiz_starter' ? stats.quizzesCompleted :
              a.id === 'perfect_score' ? stats.perfectQuizzes :
              a.id === 'streak_master' ? stats.maxStreak :
              a.id.includes('explorer') || a.id === 'first_steps' || a.id === 'world_traveler' || a.id === 'vexillology_expert' ? stats.viewedFlags.length : 0
  })), [achievementsBase, unlockedIds, stats]);

  useEffect(() => {
    localStorage.setItem('user_stats', JSON.stringify(stats));
    localStorage.setItem('unlocked_achievements', JSON.stringify(unlockedIds));
  }, [stats, unlockedIds]);

  // Monitorar novos desbloqueios
  useEffect(() => {
    const toUnlock: string[] = [];

    if (stats.viewedFlags.length >= 1) toUnlock.push('first_steps');
    if (stats.viewedFlags.length >= 50) toUnlock.push('world_traveler');
    if (stats.viewedFlags.length >= 150) toUnlock.push('vexillology_expert');
    if (stats.quizzesCompleted >= 1) toUnlock.push('quiz_starter');
    if (stats.perfectQuizzes >= 1) toUnlock.push('perfect_score');
    if (stats.maxStreak >= 10) toUnlock.push('streak_master');
    if (stats.favoritesCount >= 10) toUnlock.push('curator');
    if (stats.flagsDesigned >= 1) toUnlock.push('flag_artist');

    const newlyUnlockedIds = toUnlock.filter(id => !unlockedIds.includes(id));

    if (newlyUnlockedIds.length > 0) {
      setUnlockedIds(prev => [...prev, ...newlyUnlockedIds]);

      const newAchObjs = newlyUnlockedIds.map(id => achievementsBase.find(a => a.id === id)).filter((a): a is Achievement => !!a);
      setNotificationQueue(prev => [...prev, ...newAchObjs]);
    }
  }, [stats, unlockedIds, achievementsBase]);

  const trackFlagView = useCallback((cca3: string) => {
    setStats(prev => {
      if (prev.viewedFlags.includes(cca3)) return prev;
      return { ...prev, viewedFlags: [...prev.viewedFlags, cca3] };
    });
  }, []);

  const trackQuizResult = useCallback((score: number, total: number, streak: number) => {
    setStats(prev => ({
      ...prev,
      quizzesCompleted: prev.quizzesCompleted + 1,
      perfectQuizzes: score === total ? prev.perfectQuizzes + 1 : prev.perfectQuizzes,
      maxStreak: Math.max(prev.maxStreak, streak)
    }));
  }, []);

  const trackFavorite = useCallback((count: number) => {
    setStats(prev => (prev.favoritesCount === count ? prev : { ...prev, favoritesCount: count }));
  }, []);

  const trackDesign = useCallback(() => {
    setStats(prev => ({ ...prev, flagsDesigned: prev.flagsDesigned + 1 }));
  }, []);

  const popNotification = useCallback(() => {
    setNotificationQueue(prev => prev.slice(1));
  }, []);

  const unlockAchievement = useCallback((id: string) => setUnlockedIds(prev => prev.includes(id) ? prev : [...prev, id]), []);

  return (
    <AchievementContext.Provider value={{ 
      achievements: achievementsList, 
      stats, 
      unlockAchievement,
      trackFlagView,
      trackQuizResult,
      trackFavorite,
      trackDesign,
      notificationQueue,
      popNotification
    }}>
      {children}
    </AchievementContext.Provider>
  );
};

export const useAchievements = () => {
  const context = useContext(AchievementContext);
  if (!context) throw new Error('useAchievements must be used within AchievementProvider');
  return context;
};

import React, { useEffect, useState, useRef } from 'react';
import { useAchievements, Achievement } from '../context/AchievementContext';
import { useLanguage } from '../context/LanguageContext';

const AchievementToast: React.FC = () => {
  const { notificationQueue, popNotification } = useAchievements();
  const { t } = useLanguage();

  const [current, setCurrent] = useState<Achievement | null>(null);
  const [visible, setVisible] = useState(false);
  const isAnimating = useRef(false);

  useEffect(() => {
    // Se houver itens na fila e não estivermos animando
    if (notificationQueue.length > 0 && !isAnimating.current) {
      isAnimating.current = true;

      const nextAchievement = notificationQueue[0];
      setCurrent(nextAchievement);

      // Remover da fila global para permitir que outros componentes saibam que foi "consumido"
      popNotification();

      // Sequência de animação
      // 1. Mostrar
      const showTimeout = setTimeout(() => {
        setVisible(true);
      }, 50);

      // 2. Esconder após 10 segundos
      const hideTimeout = setTimeout(() => {
        setVisible(false);

        // 3. Limpar após a transição CSS terminar
        const cleanupTimeout = setTimeout(() => {
          setCurrent(null);
          isAnimating.current = false;
        }, 800);

        return () => clearTimeout(cleanupTimeout);
      }, 10000);

      return () => {
        clearTimeout(showTimeout);
        clearTimeout(hideTimeout);
      };
    }
  }, [notificationQueue, popNotification]);

  if (!current) return null;

  return (
    <div 
      className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] transition-all duration-700 transform ease-out
        ${visible ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-12 scale-90 pointer-events-none'}`}
    >
      <div className="bg-white dark:bg-slate-800 border-2 border-amber-400 shadow-[0_20px_50px_rgba(0,0,0,0.3)] dark:shadow-[0_20px_50px_rgba(0,0,0,0.5)] rounded-2xl p-4 flex items-center gap-4 min-w-[320px] max-w-[90vw] overflow-hidden relative">
        {/* Barra de progresso visual decrescente */}
        <div 
          className="absolute top-0 left-0 h-1 bg-amber-400 transition-all duration-[10000ms] ease-linear"
          style={{ width: visible ? '100%' : '0%' }}
        ></div>

        <div className="text-4xl flex-shrink-0 animate-bounce">{current.icon}</div>
        <div className="flex-grow min-w-0">
          <p className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest truncate">
            {t('achievementUnlocked')}
          </p>
          <h4 className="text-base font-bold text-slate-900 dark:text-white leading-tight truncate">
            {t(current.titleKey)}
          </h4>
          <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2">
            {t(current.descKey)}
          </p>
        </div>

        <button 
          onClick={() => setVisible(false)}
          className="ml-2 p-1 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors"
          aria-label="Fechar"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>
    </div>
  );
};

