const Header: React.FC<HeaderProps> = ({ currentView, setView, scrollProgress }) => {
    const { t } = useLanguage();
    const navRef = useRef<HTMLDivElement>(null);
    const [magicLineStyle, setMagicLineStyle] = useState({});

    const navItems = [
        { id: 'explorer', label: t('explorer') },
        { id: 'map', label: t('mapTitle') },
        { id: 'discover', label: t('discoverTitle') },
        { id: 'quiz', label: t('quizTitle') },
    ];

    useEffect(() => {
        const timer = setTimeout(() => {
            if (navRef.current) {
                const activeItem = navRef.current.querySelector(`[data-nav-id="${currentView}"]`) as HTMLElement;
                if (activeItem) {
                    setMagicLineStyle({
                        left: activeItem.offsetLeft,
                        width: activeItem.offsetWidth,
                    });
                }
            }
        }, 50);
        return () => clearTimeout(timer);
    }, [currentView, t, navItems.length]);

    return (
        <header className="fixed top-0 left-0 right-0 bg-white/80 dark:bg-slate-950/80 backdrop-blur-xl z-20 border-b border-slate-200/60 dark:border-slate-800/60 transition-colors duration-500">
            <div className="container mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex items-center justify-between h-20">
                    <div className="flex-1 flex justify-start">
                        <button onClick={() => setView('explorer')} className="flex items-center space-x-3 group" aria-label={t('headerTitle')}>
                            <WavingFlagIcon />
                            <span className="hidden sm:inline text-xl font-black text-slate-800 dark:text-slate-100 tracking-tight transition-colors">
                                {t('headerTitle')}
                            </span>
                        </button>
                    </div>

                    <div className="hidden md:block">
                        <div ref={navRef} className="relative flex items-center justify-center p-1.5 bg-slate-100 dark:bg-slate-900 rounded-2xl border border-slate-200/50 dark:border-slate-800/50 transition-colors duration-500">
                             <div className="absolute top-1.5 bottom-1.5 bg-white dark:bg-slate-800 rounded-xl shadow-sm transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1)" style={magicLineStyle}></div>
                            {navItems.map(item => (
                                <NavItem 
                                    key={item.id}
                                    label={item.label}
                                    isActive={currentView === item.id}
                                    onClick={() => setView(item.id as View)}
                                    data-nav-id={item.id}
                                />
                            ))}
                        </div>
                    </div>

                    <div className="flex-1 flex justify-end">
                        <div className="flex items-center space-x-2 sm:space-x-4">
                            <LanguageSwitcher />
                            <ThemeSwitcher />
                        </div>
                    </div>
                </div>
            </div>
            <div className="absolute bottom-[-1px] left-0 h-[2px] bg-blue-600 dark:bg-sky-400 rounded-r-full transition-all duration-300 ease-out" style={{ width: `${scrollProgress}%`, boxShadow: scrollProgress > 0 ? '0 0 10px rgba(56, 189, 248, 0.5)' : 'none' }} />
        </header>
    );
};

export default Header;

