import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import type { Country } from '../types';
import { useLanguage } from '../context/LanguageContext';
import { useDebounce } from '../hooks/useDebounce';

interface MapViewProps {
  countries: Country[];
  onCountryClick: (country: Country) => void;
}

const MapView: React.FC<MapViewProps> = ({ countries, onCountryClick }) => {
  const { t, language } = useLanguage();
  const [search, setSearch] = useState('');
  const debouncedSearch = useDebounce(search, 300);
  const [hoveredCountry, setHoveredCountry] = useState<Country | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [svgContent, setSvgContent] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Transform States
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const mapContainerRef = useRef<HTMLDivElement>(null);

  // Carregar o mapa mundi SVG otimizado
  useEffect(() => {
    fetch('https://raw.githubusercontent.com/dr5hn/countries-states-cities-database/master/svg/world.svg')
      .then(res => res.text())
      .then(data => {
        // Limpar o SVG de estilos internos que podem quebrar o tema dark
        const cleaned = data.replace(/style="[^"]*"/g, '');
        setSvgContent(cleaned);
        setIsLoading(false);
      })
      .catch(err => {
        console.error("Erro ao carregar mapa:", err);
        setIsLoading(false);
      });
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      const dx = e.clientX - dragStart.x;
      const dy = e.clientY - dragStart.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setDragStart({ x: e.clientX, y: e.clientY });
    }
    setTooltipPos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0) return; // Apenas botão esquerdo
    setIsDragging(true);
    setDragStart({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  const handleWheel = (e: React.WheelEvent) => {
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    setZoom(prev => Math.min(Math.max(prev * delta, 0.5), 8));
  };

  const findCountryByCode = useCallback((code: string) => {
    const upperCode = code.toUpperCase();
    return countries.find(c => c.cca2 === upperCode || c.cca3 === upperCode);
  }, [countries]);

  const onMapInteraction = (e: React.MouseEvent) => {
    const target = e.target as SVGPathElement;
    if (target.tagName === 'path') {
      const countryCode = target.getAttribute('id') || target.getAttribute('data-id') || target.getAttribute('class')?.split(' ')[0];
      if (countryCode) {
        const country = findCountryByCode(countryCode);
        if (country) {
          if (e.type === 'click') {
            onCountryClick(country);
          } else if (e.type === 'mouseover') {
            setHoveredCountry(country);
          }
        }
      }
    }
  };

  const filteredCountries = useMemo(() => {
    if (!debouncedSearch) return [];
    const lower = debouncedSearch.toLowerCase();
    return countries.filter(c => {
      const name = language === 'pt' ? c.translations.por.common : c.name.common;
      return name.toLowerCase().includes(lower);
    }).slice(0, 5);
  }, [debouncedSearch, countries, language]);

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] min-h-[500px] animate-fade-in select-none">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4 px-2">
        <div className="text-center md:text-left">
          <h1 className="text-3xl font-black text-slate-900 dark:text-white flex items-center gap-2 justify-center md:justify-start">
             <span className="text-blue-500">🌍</span> {t('mapTitle')}
          </h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">{t('mapSubtitle')}</p>
        </div>

        <div className="relative w-full md:w-80">
           <div className="relative">
              <input
                  type="text"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder={t('searchPlaceholder')}
                  className="w-full pl-10 pr-4 py-2.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
              />
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
           </div>

           {filteredCountries.length > 0 && (
             <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl z-40 overflow-hidden animate-fade-in-up-short">
                {filteredCountries.map(c => (
                  <button
                    key={c.cca3}
                    onClick={() => {
                        onCountryClick(c);
                        setSearch('');
                    }}
                    className="w-full flex items-center gap-3 px-4 py-3 hover:bg-blue-50 dark:hover:bg-slate-800 transition-colors text-left group"
                  >
                    <div className="w-8 h-5 flex-shrink-0 rounded-sm overflow-hidden shadow-sm">
                       <img src={c.flags.svg} className="w-full h-full object-cover" alt="" />
                    </div>
                    <span className="text-sm font-bold text-slate-700 dark:text-slate-200 group-hover:text-blue-600 dark:group-hover:text-sky-400 transition-colors">
                      {language === 'pt' ? c.translations.por.common : c.name.common}
                    </span>
                  </button>
                ))}
             </div>
           )}
        </div>
      </div>

      <div 
        ref={mapContainerRef}
        className="flex-grow relative bg-sky-50/30 dark:bg-slate-950/40 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 overflow-hidden shadow-inner cursor-grab active:cursor-grabbing"
        onMouseMove={handleMouseMove}
        onMouseDown={handleMouseDown}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onWheel={handleWheel}
      >
        {isLoading ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-4">
             <div className="w-12 h-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
             <p className="text-slate-400 font-bold animate-pulse uppercase tracking-widest text-xs">{t('loadingFlags')}</p>
          </div>
        ) : (
          <div 
            className="w-full h-full transition-transform duration-150 ease-out flex items-center justify-center p-8"
            style={{ 
              transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
              transformOrigin: 'center center'
            }}
            onClick={onMapInteraction}
            onMouseOver={onMapInteraction}
            onMouseOut={() => setHoveredCountry(null)}
            dangerouslySetInnerHTML={{ __html: svgContent || '' }}
          />
        )}

        {/* Controles de Zoom */}
        <div className="absolute bottom-6 right-6 flex flex-col gap-2">
            <button 
                onClick={() => setZoom(z => Math.min(z + 0.5, 8))}
                className="w-10 h-10 bg-white/80 dark:bg-slate-800/80 backdrop-blur-md rounded-xl shadow-lg border border-slate-200 dark:border-slate-700 flex items-center justify-center text-xl font-bold hover:bg-white dark:hover:bg-slate-700 transition-colors"
                title="Zoom In"
            >
                +
            </button>
            <button 
                onClick={() => setZoom(z => Math.max(z - 0.5, 0.5))}
                className="w-10 h-10 bg-white/80 dark:bg-slate-800/80 backdrop-blur-md rounded-xl shadow-lg border border-slate-200 dark:border-slate-700 flex items-center justify-center text-xl font-bold hover:bg-white dark:hover:bg-slate-700 transition-colors"
                title="Zoom Out"
            >
                -
            </button>
            <button 
                onClick={() => { setZoom(1); setPan({ x: 0, y: 0 }); }}
                className="w-10 h-10 bg-white/80 dark:bg-slate-800/80 backdrop-blur-md rounded-xl shadow-lg border border-slate-200 dark:border-slate-700 flex items-center justify-center transition-colors"
                title="Reset View"
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 110 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" /></svg>
            </button>
        </div>

        {/* Estilização Dinâmica dos Paths via CSS Injetado */}
        <style>{`
          svg { width: 100%; height: auto; display: block; filter: drop-shadow(0 10px 30px rgba(0,0,0,0.1)); pointer-events: auto; }
          path { 
            fill: #cbd5e1; 
            stroke: #94a3b8; 
            stroke-width: 0.5px; 
            transition: all 0.3s ease; 
            cursor: pointer;
            vector-effect: non-scaling-stroke;
            outline: none;
          }
          .dark path { fill: #1e293b; stroke: #334155; }
          path:hover { 
            fill: #3b82f6 !important; 
            stroke: #fff; 
            stroke-width: 1px;
            filter: drop-shadow(0 0 8px rgba(59, 130, 246, 0.8));
          }
          .dark path:hover { fill: #0ea5e9 !important; stroke: #38bdf8; }
        `}</style>
      </div>

      {/* Tooltip Card Premium */}
      {hoveredCountry && (
        <div 
          className="fixed pointer-events-none z-[100] animate-fade-in-up-short"
          style={{ 
            left: `${tooltipPos.x + 20}px`, 
            top: `${tooltipPos.y + 20}px` 
          }}
        >
          <div className="bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 min-w-[180px]">
             <div className="aspect-[3/2] w-full rounded-lg overflow-hidden mb-3 shadow-md border border-slate-100 dark:border-slate-800">
               <img src={hoveredCountry.flags.svg} className="w-full h-full object-cover" alt="" />
             </div>
             <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight truncate">
               {language === 'pt' ? hoveredCountry.translations.por.common : hoveredCountry.name.common}
             </h3>
             <p className="text-xs font-bold text-blue-500 dark:text-sky-400 mt-1 uppercase tracking-tighter">
               {hoveredCountry.continents[0]}
             </p>
             <div className="mt-3 flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-widest border-t border-slate-100 dark:border-slate-800 pt-2">
                <span>{t('population')}</span>
                <span className="text-slate-600 dark:text-slate-300">{hoveredCountry.population.toLocaleString(language)}</span>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

