    }, []);

    useEffect(() => {
        localStorage.setItem('favorites', JSON.stringify(Array.from(favorites)));
        trackFavorite(favorites.size);
    }, [favorites, trackFavorite]);

    const handleToggleFavorite = useCallback((country: Country) => {
        const countryName = language === 'pt' ? country.translations.por.common : country.name.common;
        setFavorites(prevFavorites => {
            const newFavorites = new Set(prevFavorites);
            if (newFavorites.has(country.cca3)) {
                newFavorites.delete(country.cca3);
                showToast(t('removedFromFavoritesToast', { countryName }), 'remove');
            } else {
                newFavorites.add(country.cca3);
                showToast(t('addedToFavoritesToast', { countryName }), 'add');
            }
            return newFavorites;
        });
    }, [language, showToast, t]);

    useEffect(() => {
        const handleFocusIn = (e: Event) => {
            if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
                document.body.classList.add('keyboard-visible');
            }
        };

        const handleFocusOut = (e: Event) => {
            if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
                setTimeout(() => {
                    const activeEl = document.activeElement;
                    if (!(activeEl instanceof HTMLInputElement || activeEl instanceof HTMLTextAreaElement)) {
                        document.body.classList.remove('keyboard-visible');
                    }
                }, 50);
            }
        };

        const handleScroll = () => {
            const totalScroll = document.documentElement.scrollTop;
            const windowHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
            const scroll = `${(totalScroll / windowHeight) * 100}`;
            setScrollProgress(Number(scroll));
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        document.addEventListener('focusin', handleFocusIn);
        document.addEventListener('focusout', handleFocusOut);

        return () => {
            window.removeEventListener('scroll', handleScroll);
            document.removeEventListener('focusin', handleFocusIn);
            document.removeEventListener('focusout', handleFocusOut);
        };
    }, []);

    const fetchCollections = useCallback(async (countryData: Country[]) => {
        setIsCollectionsLoading(true);
        try {
            const collections = fetchAllCollections(countryData, language);
            setCollectionsData(collections);
        } catch (error) {
            console.error("Failed to fetch collections:", error);
        } finally {
            setIsCollectionsLoading(false);
        }
    }, [language]);

    const manageFlagOfTheDay = useCallback((countryData: Country[]) => {
        if (countryData.length === 0) {
            setIsFlagOfTheDayLoading(false);
            return;
        }

        const now = new Date();
        const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
        const countryForToday = getDeterministicCountryForDate(today, countryData);
        if (!countryForToday) return;

        const storageKey = `flagOfTheDay_v3_${language}`;
        const storedFlagRaw = localStorage.getItem(storageKey);
        if (storedFlagRaw) {
            try {
                const storedFlag: StoredFlagOfTheDay = JSON.parse(storedFlagRaw);
                if (storedFlag.date === today && storedFlag.country.cca3 === countryForToday.cca3) {
                    setFlagOfTheDay({ country: storedFlag.country, title: storedFlag.title });
                    setIsFlagOfTheDayLoading(false);
                    return;
                }
            } catch (e) {
                console.error("Corrupted flag of the day in cache, removing it.", e);
                localStorage.removeItem(storageKey);
            }
        }

        const curatedTitle = FLAG_OF_THE_DAY_TITLES[countryForToday.cca3]?.[language];
        const fallbackTitle = language === 'pt' ? countryForToday.translations.por.common : countryForToday.name.common;
        const title = curatedTitle || fallbackTitle;

        const flagDayData = { country: countryForToday, title };
        setFlagOfTheDay(flagDayData);

        try {
            const newStoredFlag: StoredFlagOfTheDay = { date: today, ...flagDayData };
            localStorage.setItem(storageKey, JSON.stringify(newStoredFlag));
        } catch (error) {
            console.error("Failed to cache flag of the day data.", error);
        }

        setIsFlagOfTheDayLoading(false);

    }, [language]);

    const manageUniqueFlagOfTheDay = useCallback((countryData: Country[]) => {
        if (countryData.length === 0) {
            setIsUniqueFlagOfTheDayLoading(false);
            return;
        }

        const uniqueCountries = countryData.filter(c => UNIQUE_FLAG_CCAS.includes(c.cca3));
        if (uniqueCountries.length === 0) {
            setIsUniqueFlagOfTheDayLoading(false);
            return;
        }

        const now = new Date();
        const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

        const countryForToday = getDeterministicCountryForDate(today, uniqueCountries);
        if (!countryForToday) return;

        const storageKey = `uniqueFlagOfTheDay_${language}`;
        const storedFlagRaw = localStorage.getItem(storageKey);
        if (storedFlagRaw) {
            try {
                const storedFlag: StoredUniqueFlagOfTheDay = JSON.parse(storedFlagRaw);
                if (storedFlag.date === today && storedFlag.country.cca3 === countryForToday.cca3) {
                    setUniqueFlagOfTheDay({ country: storedFlag.country, descriptionKey: storedFlag.descriptionKey });
                    setIsUniqueFlagOfTheDayLoading(false);
                    return;
                }
            } catch (e) {
                localStorage.removeItem(storageKey);
            }
        }

        const descriptionKeyMap: { [key: string]: UniqueFlagDescriptionKey } = {
            'NPL': 'nepalFlagDesc',
            'CHE': 'switzerlandFlagDesc',
            'VAT': 'vaticanFlagDesc',
            'PRY': 'paraguayFlagDesc',
            'DNK': 'denmarkFlagDesc',
            'PHL': 'philippinesFlagDesc',
            'MOZ': 'mozambiqueFlagDesc',
            'QAT': 'qatarFlagDesc',
            'BLZ': 'belizeFlagDesc',
            'CYP': 'cyprusFlagDesc',
            'BRA': 'brazilFlagDesc',
            'AUT': 'austriaFlagDesc',
            'LSO': 'lesothoFlagDesc',
            'KHM': 'cambodiaFlagDesc',
            'TKM': 'turkmenistanFlagDesc',
            'LKA': 'sriLankaFlagDesc',
            'CAN': 'canadaFlagDesc',
            'ZAF': 'southAfricaFlagDesc',
            'DOM': 'dominicanRepublicFlagDesc',
            'JAM': 'jamaicaFlagDesc',
            'NOR': 'norwayFlagDesc',
            'UGA': 'ugandaFlagDesc',
            'BTN': 'bhutanFlagDesc',
            'LBY': 'libyaFlagDesc',
            'SAU': 'saudiArabiaFlagDesc',
            'KIR': 'kiribatiFlagDesc',
            'DMA': 'dominicaFlagDesc',
            'SWZ': 'eswatiniFlagDesc',
            'KOR': 'southKoreaFlagDesc',
            'LBN': 'lebanonFlagDesc',
            'KEN': 'kenyaFlagDesc',
            'GRD': 'grenadaFlagDesc',
            'MEX': 'mexicoFlagDesc',
            'KGZ': 'kyrgyzstanFlagDesc',
            'ATG': 'antiguaBarbudaFlagDesc',
            'SYC': 'seychellesFlagDesc',
            'VUT': 'vanuatuFlagDesc',
            'ERI': 'eritreaFlagDesc'
        };
        const descriptionKey = descriptionKeyMap[countryForToday.cca3];

        const uniqueFlagData = { country: countryForToday, descriptionKey };
        setUniqueFlagOfTheDay(uniqueFlagData);

        try {
            const newStoredFlag: StoredUniqueFlagOfTheDay = { date: today, ...uniqueFlagData };
            localStorage.setItem(storageKey, JSON.stringify(newStoredFlag));
        } catch (error) {
            console.error("Failed to cache unique flag of the day data.", error);
        }

        setIsUniqueFlagOfTheDayLoading(false);

    }, [language]);

    const loadData = useCallback(async () => {
        try {
            setIsLoading(true);
            setError(null);
            const unsortedData = await fetchCountries();
            const data = [...unsortedData].sort((a, b) => a.cca3.localeCompare(b.cca3));
            setCountries(data);
            fetchCollections(data);
            manageFlagOfTheDay(data);
            manageUniqueFlagOfTheDay(data);
        } catch (err: any) {
            setError(t(err.message) || t('fetchError'));
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    }, [t, fetchCollections, manageFlagOfTheDay, manageUniqueFlagOfTheDay]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const handleCardClick = (country: Country) => {
        if (isCompareModeActive) {
            setComparisonList(prev => {
                const isAlreadySelected = prev.some(c => c.cca3 === country.cca3);
                if (isAlreadySelected) {
                    return prev.filter(c => c.cca3 !== country.cca3);
                }
                if (prev.length < 2) {
                    return [...prev, country];
                }
                return prev;
            });
        } else {
            setSelectedCountry(country);
            trackFlagView(country.cca3);
        }
    };

    const handleCloseModal = () => {
        setSelectedCountry(null);
    };

    const handleClearComparison = () => setComparisonList([]);
    const handleOpenCompareModal = () => setIsCompareModalOpen(true);
    const handleCloseCompareModal = () => setIsCompareModalOpen(false);

    const handleToggleCompareMode = useCallback(() => {
        setIsCompareModeActive(prev => {
            const nextState = !prev;
            if (!nextState) {
                setComparisonList([]);
            }
            return nextState;
        });
    }, []);

    const filteredCountries = useMemo(() => {
        let result = [...countries];

        if (selectedContinent !== 'All') {
            if (selectedContinent === 'Favorites') {
                result = result.filter(country => favorites.has(country.cca3));
            } else {
                result = result.filter(country => country.continents.includes(selectedContinent));
            }
        }

        if (debouncedSearchQuery.trim()) {
            const lowerCaseQuery = debouncedSearchQuery.toLowerCase();
            result = result.filter(country => {
                 const commonName = language === 'pt' ? country.translations.por.common : country.name.common;
                 const officialName = language === 'pt' ? country.translations.por.official : country.name.official;
                 return commonName.toLowerCase().includes(lowerCaseQuery) ||
                        officialName.toLowerCase().includes(lowerCaseQuery) ||
                        country.cca3.toLowerCase().includes(lowerCaseQuery);
            });
        }

        return [...result].sort((a, b) => {
            const nameA = language === 'pt' ? a.translations.por.common : a.name.common;
            const nameB = language === 'pt' ? b.translations.por.common : b.name.common;

            switch (sortOrder) {
                case 'name_desc':
                    return nameB.localeCompare(nameA);
                case 'pop_desc':
                    return b.population - a.population;
                case 'pop_asc':
                    return a.population - b.population;
                case 'area_desc':
                    return b.area - a.area;
                case 'area_asc':
                    return a.area - b.area;
                case 'name_asc':
                default:
                    return nameA.localeCompare(nameB);
            }
        });
    }, [countries, selectedContinent, language, debouncedSearchQuery, favorites, sortOrder]);

    const renderContent = () => {
        switch (view) {
            case 'explorer':
                return (
                    <ExplorerContent
                        countries={countries}
                        filteredCountries={filteredCountries}
                        isLoading={isLoading}
                        error={error}
                        flagOfTheDay={flagOfTheDay}
                        isFlagOfTheDayLoading={isFlagOfTheDayLoading}
                        handleCardClick={handleCardClick}
                        favorites={favorites}
                        onToggleFavorite={handleToggleFavorite}
                        selectedContinent={selectedContinent}
                        setSelectedContinent={setSelectedContinent}
                        searchQuery={searchQuery}
                        setSearchQuery={setSearchQuery}
                        isCompareModeActive={isCompareModeActive}
                        handleToggleCompareMode={handleToggleCompareMode}
                        sortOrder={sortOrder}
                        setSortOrder={setSortOrder}
                        comparisonList={comparisonList}
                        onRetry={loadData}
                    />
                );
            case 'map':
                return <MapView countries={countries} onCountryClick={handleCardClick} />;
            case 'quiz':
                return <QuizView countries={countries} onBackToExplorer={() => setView('explorer')} />;
            case 'discover':
                return <DiscoverView 
                    countries={countries}
                    collections={collectionsData}
                    isLoading={isCollectionsLoading}
                    onCardClick={handleCardClick}
                    favorites={favorites}
                    onToggleFavorite={handleToggleFavorite}
                    uniqueFlagOfTheDay={uniqueFlagOfTheDay}
                    isUniqueFlagOfTheDayLoading={isUniqueFlagOfTheDayLoading}
                />;
            case 'designer':
                return <DesignerView />;
            default:
                return null;
        }
    }

    return (
        <div className="min-h-screen flex flex-col">
            <Header currentView={view} setView={setView} scrollProgress={scrollProgress} />
            <main className="flex-grow pt-20">
                 <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-8">
                     <Suspense fallback={<PageLoader />}>
                        {renderContent()}
                    </Suspense>
                 </div>
            </main>
            <Suspense fallback={null}>
                {selectedCountry && (
                    <FlagModal 
                        country={selectedCountry}
                        onClose={handleCloseModal}
                        isFavorite={favorites.has(selectedCountry.cca3)}
                        onToggleFavorite={handleToggleFavorite}
                    />
                )}
                {isCompareModalOpen && comparisonList.length === 2 && (
                     <CompareModal 
                        countries={[comparisonList[0], comparisonList[1]]}
                        onClose={handleCloseCompareModal}
                    />
                )}
            </Suspense>
            <Footer />
            <ScrollToTopButton />
            {view === 'explorer' && isCompareModeActive && (
                <CompareTray 
                    comparisonList={comparisonList}
                    onCompare={handleOpenCompareModal}
                    onClear={handleClearComparison}
                />
            )}
            {!(view === 'explorer' && isCompareModeActive) && <BottomNav currentView={view} setView={setView} />}
            <Toast info={toastInfo} isVisible={isToastVisible} />
            <AchievementToast />
        </div>
    );
};

const App: React.FC = () => (
    <AchievementProvider>
        <AppContent />
    </AchievementProvider>
);

export default App;

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback, useMemo, useRef } from 'react';

export interface Achievement {
  id: string;
  titleKey: string;
  descKey: string;
  icon: string;
  category: 'explorer' | 'quiz' | 'collector' | 'designer';
  isUnlocked: boolean;
  progress?: number;
  maxProgress?: number;
}

interface UserStats {
  viewedFlags: string[];
  quizzesCompleted: number;
  perfectQuizzes: number;
  maxStreak: number;
  favoritesCount: number;
  flagsDesigned: number;
}

interface AchievementContextType {
  achievements: Achievement[];
  stats: UserStats;
  unlockAchievement: (id: string) => void;
  trackFlagView: (cca3: string) => void;
  trackQuizResult: (score: number, total: number, streak: number) => void;
  trackFavorite: (count: number) => void;
  trackDesign: () => void;
  notificationQueue: Achievement[];
  popNotification: () => void;
}

const INITIAL_STATS: UserStats = {
  viewedFlags: [],
  quizzesCompleted: 0,
  perfectQuizzes: 0,
  maxStreak: 0,
  favoritesCount: 0,
  flagsDesigned: 0,
};

const AchievementContext = createContext<AchievementContextType | undefined>(undefined);

export const AchievementProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('user_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });

  const [unlockedIds, setUnlockedIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('unlocked_achievements');
    return saved ? JSON.parse(saved) : [];
  });

  // Usamos ref para rastrear o que já foi enviado para a fila de notificações e evitar duplicatas ou perdas
  const notifiedIdsRef = useRef<Set<string>>(new Set(
    JSON.parse(localStorage.getItem('unlocked_achievements') || '[]')
  ));

  const [notificationQueue, setNotificationQueue] = useState<Achievement[]>([]);

  /**
   * FIX: Added explicit type and used "as const" for category to resolve type mismatch.
   */
  const achievementsBase = useMemo(() => [
    { id: 'first_steps', titleKey: 'achFirstStepsTitle', descKey: 'achFirstStepsDesc', icon: '👣', category: 'explorer' as const, maxProgress: 1 },
    { id: 'world_traveler', titleKey: 'achWorldTravelerTitle', descKey: 'achWorldTravelerDesc', icon: '🌍', category: 'explorer' as const, maxProgress: 50 },
    { id: 'vexillology_expert', titleKey: 'achVexExpertTitle', descKey: 'achVexExpertDesc', icon: '🎓', category: 'explorer' as const, maxProgress: 150 },
    { id: 'quiz_starter', titleKey: 'achQuizStarterTitle', descKey: 'achQuizStarterDesc', icon: '📝', category: 'quiz' as const, maxProgress: 1 },
    { id: 'perfect_score', titleKey: 'achPerfectScoreTitle', descKey: 'achPerfectScoreDesc', icon: '✨', category: 'quiz' as const, maxProgress: 1 },
    { id: 'streak_master', titleKey: 'achStreakMasterTitle', descKey: 'achStreakMasterDesc', icon: '🔥', category: 'quiz' as const, maxProgress: 10 },
    { id: 'curator', titleKey: 'achCuratorTitle', descKey: 'achCuratorDesc', icon: '💖', category: 'collector' as const, maxProgress: 10 },
    { id: 'flag_artist', titleKey: 'achArtistTitle', descKey: 'achArtistDesc', icon: '🎨', category: 'designer' as const, maxProgress: 1 },
  ], []);

  const achievementsList: Achievement[] = useMemo(() => achievementsBase.map(a => ({
    ...a,
    isUnlocked: unlockedIds.includes(a.id),
    progress: a.id === 'curator' ? stats.favoritesCount :
              a.id === 'flag_artist' ? stats.flagsDesigned :
              a.id === 'quiz_starter' ? stats.quizzesCompleted :
              a.id === 'perfect_score' ? stats.perfectQuizzes :
              a.id === 'streak_master' ? stats.maxStreak :
              a.id === 'first_steps' || a.id === 'world_traveler' || a.id === 'vexillology_expert' ? stats.viewedFlags.length : 0
  })), [achievementsBase, unlockedIds, stats]);

  useEffect(() => {
    localStorage.setItem('user_stats', JSON.stringify(stats));
    localStorage.setItem('unlocked_achievements', JSON.stringify(unlockedIds));
  }, [stats, unlockedIds]);

  // Checagem de novas conquistas centralizada
  useEffect(() => {
    const checkUnlocks = () => {
      const toUnlock: string[] = [];

      if (stats.viewedFlags.length >= 1) toUnlock.push('first_steps');
      if (stats.viewedFlags.length >= 50) toUnlock.push('world_traveler');
      if (stats.viewedFlags.length >= 150) toUnlock.push('vexillology_expert');
      if (stats.quizzesCompleted >= 1) toUnlock.push('quiz_starter');
      if (stats.perfectQuizzes >= 1) toUnlock.push('perfect_score');
      if (stats.maxStreak >= 10) toUnlock.push('streak_master');
      if (stats.favoritesCount >= 10) toUnlock.push('curator');
      if (stats.flagsDesigned >= 1) toUnlock.push('flag_artist');

      const newUnlocks = toUnlock.filter(id => !notifiedIdsRef.current.has(id));

      if (newUnlocks.length > 0) {
        newUnlocks.forEach(id => notifiedIdsRef.current.add(id));
        setUnlockedIds(Array.from(notifiedIdsRef.current));

        /**
         * FIX: Ensure the notification queue receives full Achievement objects to satisfy the state type.
         */
        const newAchObjs = newUnlocks
          .map(id => {
            const base = achievementsBase.find(a => a.id === id);
            if (!base) return null;
            const ach: Achievement = {
              ...base,
              isUnlocked: true,
              progress: base.maxProgress,
            };
            return ach;
          })
          .filter((a): a is Achievement => a !== null);

        setNotificationQueue(prev => [...prev, ...newAchObjs]);
      }
    };

    checkUnlocks();
  }, [stats, achievementsBase]);

  const trackFlagView = useCallback((cca3: string) => {
    setStats(prev => {
      if (prev.viewedFlags.includes(cca3)) return prev;
      return { ...prev, viewedFlags: [...prev.viewedFlags, cca3] };
    });
  }, []);

  const trackQuizResult = useCallback((score: number, total: number, streak: number) => {
    setStats(prev => ({
      ...prev,
      quizzesCompleted: prev.quizzesCompleted + 1,
      perfectQuizzes: score === total ? prev.perfectQuizzes + 1 : prev.perfectQuizzes,
      maxStreak: Math.max(prev.maxStreak, streak)
    }));
  }, []);

  const trackFavorite = useCallback((count: number) => {
    setStats(prev => ({ ...prev, favoritesCount: count }));
  }, []);

  const trackDesign = useCallback(() => {
    setStats(prev => ({ ...prev, flagsDesigned: prev.flagsDesigned + 1 }));
  }, []);

  const popNotification = useCallback(() => {
    setNotificationQueue(prev => prev.slice(1));
  }, []);

  const unlockAchievement = useCallback((id: string) => {
    if (!notifiedIdsRef.current.has(id)) {
      notifiedIdsRef.current.add(id);
      setUnlockedIds(Array.from(notifiedIdsRef.current));
    }
  }, []);

  return (
    <AchievementContext.Provider value={{ 
      achievements: achievementsList, 
      stats, 
      unlockAchievement,
      trackFlagView,
      trackQuizResult,
      trackFavorite,
      trackDesign,
      notificationQueue,
      popNotification
    }}>
      {children}
    </AchievementContext.Provider>
  );
};

export const useAchievements = () => {
  const context = useContext(AchievementContext);
  if (!context) throw new Error('useAchievements must be used within AchievementProvider');
  return context;
};

import React, { useMemo } from 'react';
import type { Country } from '../types';
import { useLanguage } from '../context/LanguageContext';

interface FlagCardProps {
    country: Country;
    onCardClick: (country: Country) => void;
    isCompareModeActive?: boolean;
    isSelectedForCompare?: boolean;
    isFavorite?: boolean;
    onToggleFavorite?: (country: Country) => void;
}

const FlagCard: React.FC<FlagCardProps> = ({ 
    country, 
    onCardClick, 
    isCompareModeActive = false, 
    isSelectedForCompare = false,
    isFavorite = false,
    onToggleFavorite = (_country: Country) => {}
}) => {
    const { language, t } = useLanguage();
    const animationDelay = useMemo(() => `${Math.random() * 200}ms`, []);

    const commonName = language === 'pt' ? country.translations.por.common : country.name.common;
    const continent = country.continents[0];

    const ariaLabel = isCompareModeActive 
        ? t('selectForComparison', { countryName: commonName })
        : t('viewDetailsFor', { countryName: commonName });

    const cardContainerClasses = `
        relative bg-white dark:bg-slate-900 rounded-[2rem] shadow-xl border border-slate-200/50 dark:border-slate-800/50
        transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1) group overflow-hidden 
        opacity-0 animate-fade-in-up aspect-[3/4] will-change-transform
        ${isCompareModeActive 
            ? `cursor-pointer ${isSelectedForCompare ? 'ring-4 ring-blue-500 ring-offset-4 dark:ring-offset-slate-950 scale-[0.98]' : 'hover:scale-[1.02]'}`
            : 'cursor-pointer hover:-translate-y-3 hover:shadow-[0_20px_50px_-12px_rgba(0,0,0,0.3)] dark:hover:border-slate-700'
        }
    `;

    return (
        <div 
            className={cardContainerClasses}
            style={{ animationDelay }}
            onClick={() => onCardClick(country)}
            role="button"
            tabIndex={0}
            onKeyPress={(e) => { if (e.key === 'Enter') onCardClick(country) }}
            aria-label={ariaLabel}
            aria-pressed={isSelectedForCompare}
        >
            {/* Background Image with Hover Effect */}
            <div className="absolute inset-0 bg-slate-100 dark:bg-slate-800 transition-colors duration-500">
                <img
                    src={country.flags.svg}
                    alt={country.flags.alt || `Flag of ${commonName}`}
                    className="absolute inset-0 w-full h-full object-cover scale-105 group-hover:scale-125 transition-transform duration-1000 ease-out"
                    loading="lazy"
                />
                {/* Dark overlay that appears on hover */}
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors duration-500"></div>
            </div>

            {/* Top Badges */}
            <div className="absolute top-4 left-4 right-4 flex justify-between items-start z-10">
                <div className="flex flex-col gap-2">
                    <span className="px-3 py-1 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md rounded-full text-[10px] font-black uppercase tracking-widest text-slate-700 dark:text-slate-300 shadow-sm border border-white/20">
                        {continent}
                    </span>
                    {isSelectedForCompare && (
                        <div className="w-8 h-8 bg-blue-600 text-white rounded-full flex items-center justify-center shadow-lg animate-bounce ring-2 ring-white/30">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                        </div>
                    )}
                </div>

                <button
                    onClick={(e) => {
                        e.stopPropagation();
