import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import type { Country } from '../types';
import { useLanguage } from '../context/LanguageContext';
import { useDebounce } from '../hooks/useDebounce';

interface MapViewProps {
  countries: Country[];
  onCountryClick: (country: Country) => void;
}

const MapView: React.FC<MapViewProps> = ({ countries, onCountryClick }) => {
  const { t, language } = useLanguage();
  const [search, setSearch] = useState('');
  const debouncedSearch = useDebounce(search, 300);
  const [hoveredCountry, setHoveredCountry] = useState<Country | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [svgContent, setSvgContent] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Transform States
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const mapContainerRef = useRef<HTMLDivElement>(null);

  // Carregar o mapa mundi SVG otimizado
  useEffect(() => {
    fetch('https://raw.githubusercontent.com/dr5hn/countries-states-cities-database/master/svg/world.svg')
      .then(res => res.text())
      .then(data => {
        // Limpar o SVG de estilos internos que podem quebrar o tema dark
        const cleaned = data.replace(/style="[^"]*"/g, '');
        setSvgContent(cleaned);
        setIsLoading(false);
      })
      .catch(err => {
        console.error("Erro ao carregar mapa:", err);
        setIsLoading(false);
      });
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      const dx = e.clientX - dragStart.x;
      const dy = e.clientY - dragStart.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setDragStart({ x: e.clientX, y: e.clientY });
    }
    setTooltipPos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0) return; // Apenas botão esquerdo
    setIsDragging(true);
    setDragStart({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  const handleWheel = (e: React.WheelEvent) => {
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    setZoom(prev => Math.min(Math.max(prev * delta, 0.5), 8));
  };

  const findCountryByCode = useCallback((code: string) => {
    const upperCode = code.toUpperCase();
    return countries.find(c => c.cca2 === upperCode || c.cca3 === upperCode);
  }, [countries]);

  const onMapInteraction = (e: React.MouseEvent) => {
    const target = e.target as SVGPathElement;
    if (target.tagName === 'path') {
      const countryCode = target.getAttribute('id') || target.getAttribute('data-id') || target.getAttribute('class')?.split(' ')[0];
      if (countryCode) {
        const country = findCountryByCode(countryCode);
        if (country) {
          if (e.type === 'click') {
            onCountryClick(country);
          } else if (e.type === 'mouseover') {
            setHoveredCountry(country);
          }
        }
      }
    }
  };

  const filteredCountries = useMemo(() => {
    if (!debouncedSearch) return [];
    const lower = debouncedSearch.toLowerCase();
    return countries.filter(c => {
      const name = language === 'pt' ? c.translations.por.common : c.name.common;
      return name.toLowerCase().includes(lower);
    }).slice(0, 5);
  }, [debouncedSearch, countries, language]);

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] min-h-[500px] animate-fade-in select-none">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4 px-2">
        <div className="text-center md:text-left">
          <h1 className="text-3xl font-black text-slate-900 dark:text-white flex items-center gap-2 justify-center md:justify-start">
             <span className="text-blue-500">🌍</span> {t('mapTitle')}
          </h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">{t('mapSubtitle')}</p>
        </div>

        <div className="relative w-full md:w-80">
           <div className="relative">
              <input
                  type="text"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder={t('searchPlaceholder')}
                  className="w-full pl-10 pr-4 py-2.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
              />
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
           </div>

           {filteredCountries.length > 0 && (
             <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl z-40 overflow-hidden animate-fade-in-up-short">
                {filteredCountries.map(c => (
                  <button
                    key={c.cca3}
                    onClick={() => {
