import type { Country } from '../types';
import { API_BASE_URL, API_FIELDS } from '../constants';

const API_ENDPOINT = `${API_BASE_URL}/all`;
const CACHE_KEY = 'countriesData_v4'; // Atualizado para v4 para limpar caches antigos
const CACHE_EXPIRATION_MS = 24 * 60 * 60 * 1000; // 24 horas

export const fetchCountries = async (): Promise<Country[]> => {
    // 1. Tentar obter do cache primeiro
    const cachedItem = localStorage.getItem(CACHE_KEY);
    let cachedData: Country[] | null = null;
    let isExpired = true;

    if (cachedItem) {
        try {
            const { timestamp, data } = JSON.parse(cachedItem);
            cachedData = data;
            isExpired = Date.now() - timestamp > CACHE_EXPIRATION_MS;

            // Se não expirou e tem dados válidos, retorna imediatamente
            if (!isExpired && data && Array.isArray(data) && data.length > 0) {
                return data;
            }
        } catch (error) {
            console.error("Error parsing cached country data", error);
            localStorage.removeItem(CACHE_KEY);
        }
    }

    // 2. Tentar buscar da API com estratégia de fallback
    const executeFetch = async (useFields: boolean): Promise<Country[]> => {
        const url = useFields 
            ? `${API_ENDPOINT}?fields=${API_FIELDS.join(',')}`
            : API_ENDPOINT;

        console.log(`Fetching countries: ${useFields ? 'with fields filter' : 'all data (fallback)'}`);

        try {
            const response = await fetch(url);

            if (!response.ok) {
                // Se falhou com 400 usando filtros, tenta sem filtros
                if (response.status === 400 && useFields) {
                    console.warn("API returned 400 with fields filter, retrying without filter...");
                    return executeFetch(false);
                }
                throw new Error(`HTTP error! status: ${response.status}`);
            }

            const data = await response.json();
            return Array.isArray(data) ? data : [];
        } catch (err) {
            // Se falhou por rede ou outro erro e estávamos usando campos, tenta sem campos
            if (useFields) {
                return executeFetch(false);
            }
            throw err;
        }
    };

    try {
        const data = await executeFetch(true);

        if (data && data.length > 0) {
            // Atualizar cache
            try {
                const cachePayload = {
                    timestamp: Date.now(),
                    data: data,
                };
                localStorage.setItem(CACHE_KEY, JSON.stringify(cachePayload));
            } catch (error) {
                console.error("Failed to update cache", error);
            }
            return data;
        }
    } catch (error) {
        console.error("API fetch failed completely", error);

        // 3. Fallback final: Se a API falhou mas temos dados em cache (mesmo expirados), use-os
        if (cachedData && Array.isArray(cachedData) && cachedData.length > 0) {
            console.log("Using expired cache as emergency fallback");
            return cachedData;
        }

        // Se nada funcionou, propaga um erro amigável
        throw new Error('Não foi possível carregar os dados das bandeiras. Verifique sua conexão com a internet.');
    }

    return [];
};

import type { Country } from '../types';
import { API_BASE_URL, API_FIELDS } from '../constants';

const CACHE_KEY = 'countries_data_v6';
const CACHE_EXPIRATION_MS = 24 * 60 * 60 * 1000; // 24 hours

/**
 * Fetches country data from the REST Countries API.
 * Uses a fields filter for efficiency, but falls back to a full fetch if filtered fetch fails.
 * Implements a local storage cache to reduce API calls and improve performance.
 */
export const fetchCountries = async (): Promise<Country[]> => {
    // 1. Check for valid cached data
    const cached = localStorage.getItem(CACHE_KEY);
    if (cached) {
        try {
            const { timestamp, data } = JSON.parse(cached);
            const isExpired = Date.now() - timestamp > CACHE_EXPIRATION_MS;

            // If data is fresh and valid, return it
            if (!isExpired && Array.isArray(data) && data.length > 0) {
                return data;
            }
        } catch (e) {
            console.warn("Corrupted cache found, removing...");
            localStorage.removeItem(CACHE_KEY);
        }
    }

    // 2. Fetch from API
    const executeFetch = async (url: string): Promise<Country[]> => {
        const response = await fetch(url);
        if (!response.ok) {
            // Throwing status to be caught by the retry logic
            throw new Error(`API_ERROR_${response.status}`);
        }
        const data = await response.json();
        if (!Array.isArray(data)) {
            throw new Error('INVALID_DATA_FORMAT');
        }
        return data;
    };

    try {
        let data: Country[];

        try {
            // Attempt 1: Filtered fetch (more efficient)
            // Some API versions/environments have issues with specific field combinations
            const fieldsQuery = API_FIELDS.join(',');
            const filteredUrl = `${API_BASE_URL}/all?fields=${fieldsQuery}`;
            data = await executeFetch(filteredUrl);
        } catch (err: any) {
            // If filtered fetch fails (e.g. 400 error), attempt 2: Full fetch fallback
            console.warn("Filtered fetch failed (likely 400 error), attempting full fetch fallback...", err);
            const fullUrl = `${API_BASE_URL}/all`;
            data = await executeFetch(fullUrl);
        }

        // 3. Update Cache if successful
        if (data && data.length > 0) {
            try {
                localStorage.setItem(CACHE_KEY, JSON.stringify({
                    timestamp: Date.now(),
                    data
                }));
            } catch (e) {
                console.warn("Could not save to localStorage (likely quota exceeded)");
            }
            return data;
        }

        throw new Error('EMPTY_DATASET');

    } catch (error) {
        console.error("All fetch attempts failed:", error);

        // 4. Emergency Fallback: Use expired cache if available
        if (cached) {
            try {
                const { data } = JSON.parse(cached);
                if (Array.isArray(data) && data.length > 0) {
                    console.log("Using expired cache as emergency fallback");
                    return data;
                }
            } catch (e) {}
        }

        // 5. Throw error key for translation
        throw new Error('api_fetch_error');
    }
};

