const CACHE_KEY = 'countries_data_v10'; // Nova versão para limpar caches possivelmente problemáticos
const CACHE_EXPIRATION_MS = 24 * 60 * 60 * 1000; // 24 horas

export const fetchCountries = async (): Promise<Country[]> => {
    // 1. Tentar obter do cache primeiro
    const cachedItem = localStorage.getItem(CACHE_KEY);
    if (cachedItem) {
        try {
            const { timestamp, data } = JSON.parse(cachedItem);
            const isExpired = Date.now() - timestamp > CACHE_EXPIRATION_MS;

            // Se os dados estiverem frescos, retorna imediatamente
            if (!isExpired && Array.isArray(data) && data.length > 0) {
                return data;
            }
        } catch (error) {
            console.warn("Erro ao ler cache", error);
            localStorage.removeItem(CACHE_KEY);
        }
    }

    // 2. Buscar da API com estratégia de redundância
    const executeFetch = async (useFields: boolean): Promise<Country[]> => {
        // Correção crucial: Adição do path '/all' para listar os países
        const url = useFields 
            ? `${API_BASE_URL}/all?fields=${API_FIELDS.join(',')}`
            : `${API_BASE_URL}/all`;

        const response = await fetch(url);

        if (!response.ok) {
            // Se falhar com 400 ou 404 usando campos, tenta sem filtros (algumas APIs/proxies restringem URLs longas)
            if ((response.status === 400 || response.status === 404) && useFields) {
                console.warn(`Busca filtrada falhou (${response.status}), tentando dataset completo...`);
                return executeFetch(false);
            }
            throw new Error(`API_ERROR_${response.status}`);
        }

        const data = await response.json();
        return Array.isArray(data) ? data : [];
    };

    try {
        const data = await executeFetch(true);

        if (data && data.length > 0) {
            // Atualizar cache
            try {
                localStorage.setItem(CACHE_KEY, JSON.stringify({
                    timestamp: Date.now(),
                    data: data,
                }));
            } catch (error) {
                console.warn("Falha ao salvar no cache local", error);
            }
            return data;
        }
    } catch (error) {
        console.error("Todas as tentativas de busca falharam", error);

        // 3. Fallback de Emergência: Usar cache expirado se disponível
        if (cachedItem) {
            try {
                const { data } = JSON.parse(cachedItem);
                if (Array.isArray(data) && data.length > 0) {
                    console.log("Usando cache expirado como fallback de emergência");
                    return data;
                }
            } catch (e) {}
        }

        // Relançar erro com chave para tradução na UI
        throw new Error('api_fetch_error');
    }

    return [];
};

