import type { Country } from '../types';
import { API_BASE_URL, API_FIELDS } from '../constants';

const CACHE_KEY = 'countries_data_v11';
const CACHE_EXPIRATION_MS = 24 * 60 * 60 * 1000;

export const fetchCountries = async (): Promise<Country[]> => {
    const cachedItem = localStorage.getItem(CACHE_KEY);
    if (cachedItem) {
        try {
            const { timestamp, data } = JSON.parse(cachedItem);
            const isExpired = Date.now() - timestamp > CACHE_EXPIRATION_MS;
            if (!isExpired && Array.isArray(data) && data.length > 0) {
                return data;
            }
        } catch (error) {
            localStorage.removeItem(CACHE_KEY);
        }
    }

    try {
        const url = `${API_BASE_URL}/all?fields=${API_FIELDS.join(',')}`;
        const response = await fetch(url);

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();

        if (Array.isArray(data) && data.length > 0) {
            localStorage.setItem(CACHE_KEY, JSON.stringify({
                timestamp: Date.now(),
                data: data,
            }));
            return data;
        }
    } catch (error) {
        console.error("Fetch failed", error);
        if (cachedItem) {
            try {
                const { data } = JSON.parse(cachedItem);
                return data;
            } catch (e) {}
        }
        throw new Error('api_fetch_error');
    }

    return [];
};

