import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { Country } from '../types';
import { useLanguage } from '../context/LanguageContext';
import { CONTINENT_NAMES } from '../constants';

const MAX_GUESSES = 6;
const PIXEL_LEVELS = [40, 25, 15, 8, 4, 0];

// --- Geolocation Math Helpers ---
function getDistance(lat1: number, lon1: number, lat2: number, lon2: number) {
    const R = 6371; // Earth radius in km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return Math.round(R * c);
}

function getBearing(lat1: number, lon1: number, lat2: number, lon2: number) {
    const startLat = lat1 * Math.PI / 180;
    const startLon = lon1 * Math.PI / 180;
    const destLat = lat2 * Math.PI / 180;
    const destLon = lon2 * Math.PI / 180;

    const y = Math.sin(destLon - startLon) * Math.cos(destLat);
    const x = Math.cos(startLat) * Math.sin(destLat) -
              Math.sin(startLat) * Math.cos(destLat) * Math.cos(destLon - startLon);
    let brng = Math.atan2(y, x) * 180 / Math.PI;
    return (brng + 360) % 360;
}

const normalizeString = (str: string) => str.trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

interface GuessInfo {
    name: string;
    distance: number;
    bearing: number;
    isCorrect: boolean;
}

const FlagleGame: React.FC<{ countries: Country[], onBackToMenu: () => void }> = ({ countries, onBackToMenu }) => {
    const { t, language } = useLanguage();

    const [correctCountry, setCorrectCountry] = useState<Country | null>(null);
    const [guesses, setGuesses] = useState<GuessInfo[]>([]);
    const [currentInput, setCurrentInput] = useState("");
    const [isWon, setIsWon] = useState(false);
    const [isGameOver, setIsGameOver] = useState(false);
    const [suggestions, setSuggestions] = useState<Country[]>([]);
    const [shake, setShake] = useState(false);

    const inputRef = useRef<HTMLInputElement>(null);
    const getCountryName = useCallback((c: Country) => language === 'pt' ? (c.translations?.por?.common || c.name.common) : c.name.common, [language]);

    const startNewGame = useCallback(() => {
        const playableCountries = countries.filter(c => c.latlng && c.latlng.length === 2);
        const randomCountry = playableCountries[Math.floor(Math.random() * playableCountries.length)];
        setCorrectCountry(randomCountry);
        setGuesses([]);
        setCurrentInput("");
        setIsWon(false);
        setIsGameOver(false);
        setSuggestions([]);
        setTimeout(() => inputRef.current?.focus(), 100);
    }, [countries]);

    useEffect(() => {
        startNewGame();
    }, [startNewGame]);

    const handleGuess = useCallback((country: Country) => {
        if (isGameOver || !correctCountry) return;

        const distance = getDistance(
            country.latlng[0], country.latlng[1],
            correctCountry.latlng[0], correctCountry.latlng[1]
        );
        const bearing = getBearing(
            country.latlng[0], country.latlng[1],
            correctCountry.latlng[0], correctCountry.latlng[1]
        );

        const isCorrect = country.cca3 === correctCountry.cca3;
        const newGuess: GuessInfo = {
            name: getCountryName(country),
            distance,
            bearing,
            isCorrect
        };

        setGuesses(prev => [...prev, newGuess]);
        setCurrentInput("");
        setSuggestions([]);

        if (isCorrect) {
            setIsWon(true);
            setIsGameOver(true);
        } else {
            setShake(true);
            setTimeout(() => setShake(false), 500);
            if (guesses.length + 1 >= MAX_GUESSES) {
                setIsGameOver(true);
            }
        }
    }, [isGameOver, correctCountry, guesses, getCountryName]);

    const handleInputChange = (val: string) => {
        setCurrentInput(val);
        if (val.length >= 2) {
            const normalized = normalizeString(val);
            const filtered = countries
                .filter(c => normalizeString(getCountryName(c)).includes(normalized))
                .slice(0, 5);
            setSuggestions(filtered);
        } else {
            setSuggestions([]);
        }
    };

    const pixelValue = useMemo(() => {
        if (isGameOver) return 0;
        return PIXEL_LEVELS[guesses.length] || 0;
    }, [guesses.length, isGameOver]);

    const currentHint = useMemo(() => {
        if (!correctCountry) return null;
        if (guesses.length >= 4) return `Dica: Nome começa com "${getCountryName(correctCountry).charAt(0)}"`;
        if (guesses.length >= 2) {
            const cont = correctCountry.continents[0];
            return `Dica: Localizado em ${CONTINENT_NAMES[cont]?.[language] || cont}`;
        }
        return null;
    }, [guesses.length, correctCountry, language, getCountryName]);

    return (
        <div className="max-w-xl mx-auto px-4 pb-24">
            {/* Game Header */}
            <div className="flex items-center justify-between mb-8">
                <button onClick={onBackToMenu} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
                </button>
                <h1 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">FLAGLE</h1>
                <div className="w-10"></div>
            </div>

            {/* Flag View Container */}
            <div className={`relative mb-8 group ${shake ? 'animate-bounce' : ''}`}>
                <div className="aspect-[5/3] rounded-[2rem] overflow-hidden shadow-2xl border-4 border-white dark:border-slate-800 bg-slate-100 dark:bg-slate-900">
                    {correctCountry && (
                        <img 
                            src={correctCountry.flags.svg} 
                            alt=""
                            className="w-full h-full object-cover transition-all duration-700"
                            style={{ filter: pixelValue > 0 ? `blur(${pixelValue}px) contrast(1.2) brightness(0.9)` : 'none' }}
                        />
                    )}
                </div>
                {isWon && (
                    <div className="absolute inset-0 bg-green-500/20 backdrop-blur-sm flex items-center justify-center animate-fade-in">
                        <div className="bg-white dark:bg-slate-900 p-4 rounded-full shadow-2xl border-4 border-green-500 animate-bounce">
                            <svg className="w-12 h-12 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>
                        </div>
                    </div>
                )}
            </div>

            {/* Hint Badge */}
            {currentHint && !isGameOver && (
                <div className="mb-6 text-center animate-fade-in-up">
                    <span className="px-4 py-2 bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 rounded-full text-xs font-black uppercase tracking-widest border border-amber-200 dark:border-amber-800/50">
                        {currentHint}
                    </span>
                </div>
            )}

            {/* Guesses History */}
            <div className="space-y-3 mb-8">
                {Array.from({ length: MAX_GUESSES }).map((_, i) => {
                    const guess = guesses[i];
                    return (
                        <div key={i} className={`h-14 rounded-2xl flex items-center px-4 gap-3 border-2 transition-all duration-500 ${
                            !guess ? 'bg-slate-50 dark:bg-slate-900/50 border-slate-100 dark:border-slate-800' :
                            guess.isCorrect ? 'bg-green-500 border-green-500 text-white shadow-lg shadow-green-500/20' :
                            'bg-slate-800 dark:bg-white border-slate-800 dark:border-white text-white dark:text-slate-900'
                        }`}>
                            <div className="w-8 font-black opacity-30 text-xs">{i + 1}</div>
                            {guess ? (
                                <>
                                    <div className="flex-grow font-black truncate text-sm uppercase tracking-tight">{guess.name}</div>
                                    {!guess.isCorrect && (
                                        <div className="flex items-center gap-3 font-bold text-xs whitespace-nowrap">
                                            <span>{guess.distance} km</span>
                                            <div 
                                                className="w-6 h-6 flex items-center justify-center transition-transform duration-1000"
                                                style={{ transform: `rotate(${guess.bearing}deg)` }}
                                            >
                                                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                                            </div>
                                        </div>
                                    )}
                                </>
                            ) : (
                                <div className="flex-grow h-2 bg-slate-200 dark:bg-slate-800 rounded-full opacity-50"></div>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Input & Game Over State */}
            {!isGameOver ? (
                <div className="relative group">
                    <input
                        ref={inputRef}
                        type="text"
                        value={currentInput}
                        onChange={(e) => handleInputChange(e.target.value)}
                        placeholder={t('enterCountryName')}
                        className="w-full h-16 bg-white dark:bg-slate-900 rounded-[1.5rem] px-6 font-bold shadow-xl border-4 border-slate-100 dark:border-slate-800 focus:border-blue-500 outline-none transition-all placeholder:text-slate-400"
                    />
                    {suggestions.length > 0 && (
                        <div className="absolute bottom-full mb-3 left-0 right-0 bg-white dark:bg-slate-800 rounded-3xl shadow-2xl border-2 border-slate-100 dark:border-slate-700 overflow-hidden z-50 animate-fade-in-up">
                            {suggestions.map((c) => (
                                <button
                                    key={c.cca3}
                                    onClick={() => handleGuess(c)}
                                    className="w-full h-14 px-6 text-left font-black text-sm uppercase tracking-tight hover:bg-blue-500 hover:text-white transition-colors flex items-center gap-4"
                                >
                                    <div className="w-8 h-5 rounded overflow-hidden shadow-sm flex-shrink-0">
                                        <img src={c.flags.svg} alt="" className="w-full h-full object-cover" />
                                    </div>
                                    {getCountryName(c)}
                                </button>
                            ))}
                        </div>
                    )}
                </div>
            ) : (
                <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl border-4 border-slate-100 dark:border-slate-800 text-center animate-fade-in-up">
                    <h2 className={`text-4xl font-black mb-2 ${isWon ? 'text-green-500' : 'text-red-500'}`}>
                        {isWon ? 'GÊNIO!' : 'ERROU TUDO!'}
                    </h2>
                    <p className="text-slate-500 dark:text-slate-400 font-bold mb-6">
                        O país era <span className="text-slate-900 dark:text-white">{getCountryName(correctCountry!)}</span>
                    </p>
                    <div className="flex gap-4">
                        <button 
                            onClick={startNewGame}
                            className="flex-1 h-14 bg-blue-600 text-white font-black rounded-2xl shadow-lg shadow-blue-500/30 hover:scale-105 active:scale-95 transition-all"
                        >
                            NOVA PARTIDA
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

