                ${isCompareModeActive 
                    ? `cursor-pointer ${isSelectedForCompare ? 'ring-4 ring-blue-500 ring-offset-4 dark:ring-offset-slate-950 scale-[0.97]' : 'hover:scale-[1.02] hover:ring-2 hover:ring-blue-400'}`
