                }
            `}
            style={{ animationDelay }}
            onClick={() => onCardClick(country)}
            role="button"
            tabIndex={0}
            onKeyPress={(e) => { if (e.key === 'Enter') onCardClick(country) }}
            aria-label={ariaLabel}
        >
            {/* Base Flag Image */}
            <div className="absolute inset-0 z-0">
                <img
                    src={country.flags.svg}
                    alt={country.flags.alt || t('flagOf', { country: commonName })}
                    className="w-full h-full object-cover transition-transform duration-[1.5s] cubic-bezier(0.2,1,0.2,1) group-hover:scale-125 group-hover:rotate-1"
