                    {translatedContinent}
                </span>
            </div>

            {/* Favorito Button - Estilo Premium */}
            <button
                onClick={(e) => {
                    e.stopPropagation();
                    onToggleFavorite(country);
                }}
                className={`absolute top-5 right-5 z-30 p-3.5 rounded-[1.2rem] transition-all duration-500 transform 
                    ${isFavorite 
                        ? 'bg-red-500 text-white shadow-[0_0_30px_rgba(239,68,68,0.6)] scale-110' 
                        : 'bg-black/20 text-white backdrop-blur-2xl border border-white/20 hover:bg-red-500/80 hover:border-red-400/50'
                    } 
                    hover:scale-125 active:scale-90 focus:outline-none`}
                aria-label={isFavorite ? t('removeFromFavorites') : t('addToFavorites')}
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
