const VexillologyVignettes: React.FC = () => {
    const { t } = useLanguage();

    const facts = useMemo(() => {
        try {
            return JSON.parse(t('flagFactsList'));
        } catch (e) {
            console.error("Failed to parse flag facts:", e);
            return [];
        }
    }, [t]);

    const [factIndex, setFactIndex] = useState(() => Math.floor(Math.random() * facts.length));

    const showNewFact = useCallback(() => {
        if (facts.length <= 1) return;
        let newIndex;
        do {
            newIndex = Math.floor(Math.random() * facts.length);
        } while (newIndex === factIndex);
        setFactIndex(newIndex);
    }, [factIndex, facts.length]);

    const currentFact = facts[factIndex] || '';

    const parsedFact = useMemo(() => {
        return currentFact.split('**').map((part: string, index: number) => 
            index % 2 === 1 ? <strong key={index} className="text-blue-400">{part}</strong> : part
        );
    }, [currentFact]);

    if (facts.length === 0) return null;

    return (
        <div className="relative bg-slate-900 rounded-[3rem] shadow-2xl p-10 h-full flex flex-col justify-between overflow-hidden border border-white/5">
            {/* Background pattern - Low opacity to avoid white washout */}
