interface DiscoverCarouselProps {
    title: string;
    countries: Country[];
    onCardClick: (country: Country) => void;
    favorites: Set<string>;
    onToggleFavorite: (country: Country) => void;
}

const ChevronLeftIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-800 dark:text-slate-200" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
    </svg>
);

const ChevronRightIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-800 dark:text-slate-200" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
    </svg>
);

const DiscoverCarousel: React.FC<DiscoverCarouselProps> = ({ title, countries, onCardClick, favorites, onToggleFavorite }) => {
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const [scrollState, setScrollState] = useState({ canScrollLeft: false, canScrollRight: false });
    const { t } = useLanguage();

    const checkScrollability = () => {
        const el = scrollContainerRef.current;
        if (el) {
            const canScrollLeft = el.scrollLeft > 5;
            const canScrollRight = el.scrollWidth > el.clientWidth && el.scrollLeft < el.scrollWidth - el.clientWidth - 5;
            if (canScrollLeft !== scrollState.canScrollLeft || canScrollRight !== scrollState.canScrollRight) {
                setScrollState({ canScrollLeft, canScrollRight });
            }
        }
    };

    useEffect(() => {
        const el = scrollContainerRef.current;
        if (el) {
            checkScrollability();
            el.addEventListener('scroll', checkScrollability, { passive: true });
            const resizeObserver = new ResizeObserver(checkScrollability);
            resizeObserver.observe(el);
            return () => {
                el.removeEventListener('scroll', checkScrollability);
                resizeObserver.disconnect();
            };
        }
    }, [countries]);

    const scrollBy = (factor: number) => {
        const el = scrollContainerRef.current;
        if (el) {
            el.scrollBy({ left: el.clientWidth * factor, behavior: 'smooth' });
        }
    };

    return (
        <div className="mb-16">
            <h3 className="text-3xl font-black text-slate-800 dark:text-slate-200 mb-8 tracking-tighter">
                {title}
            </h3>
             <div className="relative group">
                <div 
                    ref={scrollContainerRef} 
                    className="flex space-x-6 overflow-x-auto pb-8 -mb-8 no-scrollbar scroll-smooth"
                    style={{ WebkitOverflowScrolling: 'touch' }}
                >
                    {countries.map((country) => (
                        <div key={country.cca3} className="w-64 sm:w-72 flex-shrink-0">
                            <FlagCard 
                                country={country}
                                onCardClick={onCardClick}
                                isFavorite={favorites.has(country.cca3)}
                                onToggleFavorite={onToggleFavorite}
                            />
                        </div>
                    ))}
                </div>

                <button
                    onClick={() => scrollBy(-0.8)}
                    aria-label={t('scrollLeft')}
                    className={`absolute top-1/2 -left-6 -translate-y-1/2 z-10 p-4 bg-white dark:bg-slate-800 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all hidden md:flex items-center justify-center border border-slate-100 dark:border-slate-700 ${scrollState.canScrollLeft ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
                >
                    <ChevronLeftIcon />
                </button>
                <button
                    onClick={() => scrollBy(0.8)}
                    aria-label={t('scrollRight')}
                    className={`absolute top-1/2 -right-6 -translate-y-1/2 z-10 p-4 bg-white dark:bg-slate-800 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all hidden md:flex items-center justify-center border border-slate-100 dark:border-slate-700 ${scrollState.canScrollRight ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
                >
                    <ChevronRightIcon />
                </button>
            </div>
        </div>
    );
};


interface CollectionShowcaseProps {
    collections: { title: string; countries: Country[] }[] | null;
    isLoading: boolean;
    onCardClick: (country: Country) => void;
    favorites: Set<string>;
