            text: language === 'pt' ? 'Olá! Sou o Vexy. Posso te ajudar a encontrar bandeiras ou curiosidades. O que quer saber?' : 'Hi! I am Vexy. I can help you find flags or curiosities. What do you want to know?',
            sender: 'vexy',
            timestamp: new Date()
        }
    ]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isOpen]);

    const processMessage = (text: string) => {
        const query = text.toLowerCase().trim();
        let response = "";

        // Lógica de Processamento Local (Sem API externa)
        if (query.includes('quiz')) {
            response = language === 'pt' ? "O Quiz é ótimo! Clique no ícone de troféu ou no menu para começar um desafio." : "The Quiz is great! Click the trophy icon or menu to start a challenge.";
        } else if (query.includes('maior') || query.includes('biggest') || query.includes('popula')) {
            const top = [...countries].sort((a, b) => b.population - a.population)[0];
            const name = language === 'pt' ? (top.translations?.por?.common || top.name.common) : top.name.common;
            response = language === 'pt' 
                ? `${name} é o gigante aqui com ${top.population.toLocaleString('pt-BR')} pessoas!` 
                : `${name} is the giant here with ${top.population.toLocaleString('en-US')} people!`;
        } else if (query.includes('brasil') || query.includes('brazil')) {
            const br = countries.find(c => c.cca3 === 'BRA');
            if (br) {
                response = language === 'pt' 
                    ? "Brasil! Nossa bandeira 'Ordem e Progresso' é icônica. Quer ver os detalhes?" 
                    : "Brazil! The 'Order and Progress' flag is iconic. Want to see details?";
            }
        } else if (query.includes('ajuda') || query.includes('help')) {
            response = language === 'pt' 
                ? "Eu posso buscar países, falar sobre o Quiz ou recomendar bandeiras aleatórias!" 
                : "I can search for countries, talk about the Quiz, or recommend random flags!";
        } else {
            // Busca por nome de país genérica
            const found = countries.find(c => {
                const name = language === 'pt' ? (c.translations?.por?.common || c.name.common) : c.name.common;
                return name.toLowerCase().includes(query);
            });

            if (found) {
                const name = language === 'pt' ? (found.translations?.por?.common || found.name.common) : found.name.common;
                response = language === 'pt' 
                    ? `Encontrei ${name}! A capital é ${found.capital?.[0] || 'não informada'}. Clique para explorar!` 
                    : `Found ${name}! The capital is ${found.capital?.[0] || 'not listed'}. Click to explore!`;

                // Ação especial: Abre o modal se encontrar um específico
                setTimeout(() => onSelectCountry(found), 1500);
            } else {
                response = language === 'pt' 
                    ? "Ainda estou aprendendo sobre esse assunto. Tente perguntar sobre um país ou o 'Quiz'!" 
                    : "I'm still learning about that. Try asking about a country or the 'Quiz'!";
            }
        }

        const vexyMessage: Message = {
            id: Date.now(),
            text: response,
            sender: 'vexy',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, vexyMessage]);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        setInput('');

        // Simula tempo de "pensamento"
        setTimeout(() => processMessage(userMsg.text), 600);
    };

    return (
        <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {/* Chat Window */}
            {isOpen && (
                <div className="w-[320px] sm:w-[380px] h-[450px] bg-white dark:bg-slate-950 border-2 border-blue-500/20 rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden animate-fade-in-up pointer-events-auto mb-4 backdrop-blur-xl">
                    <div className="p-5 bg-gradient-to-r from-blue-600 to-indigo-600 flex justify-between items-center">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center text-xl animate-float">🤖</div>
                            <div>
                                <h3 className="text-white font-black text-sm tracking-tight">Vexy Assistant</h3>
                                <span className="text-blue-100 text-[9px] font-bold uppercase tracking-widest">Online</span>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="text-white/60 hover:text-white transition-colors">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>

                    <div className="flex-grow overflow-y-auto p-5 space-y-4 no-scrollbar bg-slate-50 dark:bg-slate-900/50">
                        {messages.map(m => (
                            <div key={m.id} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[80%] p-4 rounded-2xl text-xs font-bold leading-relaxed shadow-sm ${
                                    m.sender === 'user' 
                                        ? 'bg-blue-600 text-white rounded-tr-none' 
                                        : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 rounded-tl-none border border-slate-100 dark:border-slate-700'
                                }`}>
                                    {m.text}
                                </div>
                            </div>
                        ))}
                        <div ref={messagesEndRef} />
                    </div>

                    <form onSubmit={handleSubmit} className="p-4 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800 flex gap-2">
                        <input 
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder={language === 'pt' ? "Pergunte algo..." : "Ask something..."}
                            className="flex-grow bg-slate-100 dark:bg-slate-900 border-none rounded-xl px-4 py-2 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none dark:text-white"
                        />
                        <button type="submit" className="p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/20">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                        </button>
                    </form>
                </div>
            )}

            {/* Floating Toggle Button */}
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className="w-16 h-16 bg-blue-600 rounded-full shadow-[0_20px_50px_rgba(37,99,235,0.4)] flex items-center justify-center text-3xl pointer-events-auto hover:scale-110 active:scale-90 transition-all border-4 border-white dark:border-slate-800 group relative overflow-hidden"
            >
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent skew-x-[-25deg] animate-metal-shimmer"></div>
                {isOpen ? '❌' : '🤖'}
            </button>
        </div>
    );
};

