                />
            )}
            {!(view === 'explorer' && isCompareModeActive) && <BottomNav currentView={view} setView={setView} />}
            <Toast info={toastInfo} isVisible={isToastVisible} />
            <AchievementToast />
            <VexyChatbot 
                countries={countries} 
                onNavigate={(v) => setView(v)} 
                onSelectCountry={(c) => setSelectedCountry(c)}
            />
        </div>
    );
};

