export const fetchAllCollections = (allCountries: Country[], language: string): { title: string, countries: Country[] }[] => {
    if (allCountries.length === 0) {
        return [];
    }

    // Select a larger random subset of collections to display
    const generatorsToUse = shuffleArray(collectionGenerators).slice(0, 12);

    return generatorsToUse.map(generator => {
        const title = generator.title[language as 'en' | 'pt'];
        const countries = generator.getCountries(allCountries);
        // Ensure a collection is only shown if it has a reasonable number of flags
        if (countries.length > 2) {
            return { title, countries };
        }
        return null;
    }).filter((collection): collection is { title: string, countries: Country[] } => collection !== null);
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useLanguage } from '../context/LanguageContext';
import type { Country } from '../types';

interface Message {
    id: number;
    text: string;
    sender: 'user' | 'vexy';
    timestamp: Date;
}

interface VexyChatbotProps {
    countries: Country[];
    onNavigate: (view: any) => void;
    onSelectCountry: (country: Country) => void;
}

const normalize = (str: string) => str.toLowerCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

const VexyChatbot: React.FC<VexyChatbotProps> = ({ countries, onNavigate, onSelectCountry }) => {
    const { t, language } = useLanguage();
    const [isOpen, setIsOpen] = useState(false);
    const [input, setInput] = useState('');
    const [messages, setMessages] = useState<Message[]>([
        {
            id: 1,
            text: language === 'pt' 
                ? 'Olá! Sou o Vexy, seu guia oficial das bandeiras. Posso comparar dados de todos os países, encontrar capitais ou te dar sugestões. O que vamos explorar hoje?' 
                : 'Hi! I am Vexy, your official flag guide. I can compare data from all countries, find capitals, or give you suggestions. What shall we explore today?',
            sender: 'vexy',
            timestamp: new Date()
        }
    ]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen]);

    const getCountryDisplayName = useCallback((c: Country) => {
        return language === 'pt' ? (c.translations?.por?.common || c.name.common) : c.name.common;
    }, [language]);

    const processMessage = (text: string) => {
        const query = normalize(text);
        let response = "";
        let action: (() => void) | null = null;

        // --- LÓGICA DE COMANDOS ---

        // 1. Estatísticas de População
        if (query.includes('maior populacao') || query.includes('mais populoso') || query.includes('most populous')) {
            const top = [...countries].sort((a, b) => b.population - a.population)[0];
            response = language === 'pt'
                ? `O país mais populoso do meu banco de dados é ${getCountryDisplayName(top)}, com aproximadamente ${top.population.toLocaleString('pt-BR')} habitantes!`
                : `The most populous country in my database is ${getCountryDisplayName(top)}, with approximately ${top.population.toLocaleString('en-US')} people!`;
            action = () => onSelectCountry(top);
        }
        else if (query.includes('menor populacao') || query.includes('menos populoso') || query.includes('least populous')) {
            const bottom = [...countries].filter(c => c.population > 0).sort((a, b) => a.population - b.population)[0];
            response = language === 'pt'
                ? `${getCountryDisplayName(bottom)} tem a menor população registrada aqui: apenas ${bottom.population.toLocaleString('pt-BR')} pessoas.`
                : `${getCountryDisplayName(bottom)} has the smallest population recorded here: only ${bottom.population.toLocaleString('en-US')} people.`;
            action = () => onSelectCountry(bottom);
        }

        // 2. Estatísticas de Área
        else if (query.includes('maior pais') || query.includes('maior area') || query.includes('biggest country')) {
            const top = [...countries].sort((a, b) => b.area - a.area)[0];
            response = language === 'pt'
                ? `O gigante em território é ${getCountryDisplayName(top)}, cobrindo ${top.area.toLocaleString('pt-BR')} km²!`
                : `The giant in territory is ${getCountryDisplayName(top)}, covering ${top.area.toLocaleString('en-US')} km²!`;
            action = () => onSelectCountry(top);
        }
        else if (query.includes('menor pais') || query.includes('menor area') || query.includes('smallest country')) {
            const bottom = [...countries].filter(c => c.area > 0).sort((a, b) => a.area - b.area)[0];
            response = language === 'pt'
                ? `O menor de todos é ${getCountryDisplayName(bottom)}, com apenas ${bottom.area.toLocaleString('pt-BR')} km². Uma joia minúscula!`
                : `The smallest of all is ${getCountryDisplayName(bottom)}, with just ${bottom.area.toLocaleString('en-US')} km². A tiny gem!`;
            action = () => onSelectCountry(bottom);
        }

        // 3. Busca por Região
        else if (query.includes('europa') || query.includes('europe') || query.includes('africa') || query.includes('asia') || query.includes('oceania') || query.includes('america')) {
            const region = query.includes('europa') || query.includes('europe') ? 'Europe' :
                           query.includes('africa') ? 'Africa' :
                           query.includes('asia') ? 'Asia' :
                           query.includes('oceania') ? 'Oceania' : 'Americas';

            const count = countries.filter(c => c.continents.join(' ').includes(region) || c.continents.join(' ').includes('America')).length;
            response = language === 'pt'
                ? `Eu conheço ${count} bandeiras nessa região. Você pode usar o filtro de continentes no menu lateral para ver todas elas!`
                : `I know ${count} flags in that region. You can use the continent filter in the side menu to see them all!`;
        }

        // 4. Navegação
        else if (query.includes('quiz') || query.includes('jogo') || query.includes('desafio')) {
            response = language === 'pt' ? "Vou te levar para o Centro de Desafios! Prepare-se." : "I'll take you to the Challenge Center! Get ready.";
            action = () => onNavigate('quiz');
        }
        else if (query.includes('designer') || query.includes('criar') || query.includes('fazer')) {
            response = language === 'pt' ? "Abrindo a Oficina de Heráldica para você criar sua própria bandeira." : "Opening the Heraldry Workshop for you to create your own flag.";
            action = () => onNavigate('designer');
        }

        // 5. Busca Específica de País (Busca Profunda)
        else {
            const found = countries.find(c => {
                const namePT = normalize(c.translations?.por?.common || "");
                const nameOfficialPT = normalize(c.translations?.por?.official || "");
                const nameEN = normalize(c.name.common);
                const nameOfficialEN = normalize(c.name.official);
                const capital = normalize(c.capital?.[0] || "");
                const code = c.cca3.toLowerCase();

                return query === namePT || query === nameEN || 
                       query.includes(namePT) || query.includes(nameEN) ||
                       query === capital || query === code;
            });

            if (found) {
                const name = getCountryDisplayName(found);
                const cap = found.capital?.[0] || (language === 'pt' ? 'não informada' : 'not listed');
                response = language === 'pt'
                    ? `Encontrei informações sobre ${name}! A capital é ${cap} e a população é de ${found.population.toLocaleString('pt-BR')} pessoas. Quer ver a bandeira de perto?`
                    : `I found information about ${name}! The capital is ${cap} and the population is ${found.population.toLocaleString('en-US')}. Want a closer look at the flag?`;
                action = () => onSelectCountry(found);
            } else {
                // Sugestão Aleatória se não entender
                const random = countries[Math.floor(Math.random() * countries.length)];
                response = language === 'pt'
                    ? `Não entendi muito bem... que tal dar uma olhada na bandeira de ${getCountryDisplayName(random)}? Ou tente perguntar: "Qual o maior país?"`
                    : `I didn't quite catch that... how about taking a look at the flag of ${getCountryDisplayName(random)}? Or try asking: "Which is the biggest country?"`;
            }
        }

        const vexyMessage: Message = {
            id: Date.now(),
            text: response,
            sender: 'vexy',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, vexyMessage]);
        if (action) setTimeout(action, 1500);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setTimeout(() => processMessage(userMsg.text), 600);
    };

    return (
        <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
                <div className="w-[320px] sm:w-[400px] h-[500px] bg-white dark:bg-slate-950 border-2 border-blue-500/30 rounded-[2.8rem] shadow-[0_30px_100px_rgba(0,0,0,0.4)] flex flex-col overflow-hidden animate-fade-in-up pointer-events-auto mb-4 backdrop-blur-2xl">
                    <div className="p-6 bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 flex justify-between items-center relative overflow-hidden">
                        <div className="absolute inset-0 opacity-10 pointer-events-none">
                            <svg width="100%" height="100%"><pattern id="grid" width="20" height="20" patternUnits="userSpaceOnUse"><path d="M 20 0 L 0 0 0 20" fill="none" stroke="white" strokeWidth="0.5"/></pattern><rect width="100%" height="100%" fill="url(#grid)"/></svg>
                        </div>
                        <div className="flex items-center gap-4 relative z-10">
                            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center text-2xl animate-float border border-white/20 backdrop-blur-md shadow-inner">🤖</div>
                            <div>
                                <h3 className="text-white font-black text-base tracking-tight leading-none mb-1">Vexy</h3>
                                <div className="flex items-center gap-1.5">
                                    <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
                                    <span className="text-blue-100 text-[10px] font-black uppercase tracking-[0.2em]">Sincronizado</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="relative z-10 p-2 text-white/60 hover:text-white hover:bg-white/10 rounded-xl transition-all">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>

                    <div className="flex-grow overflow-y-auto p-6 space-y-5 no-scrollbar bg-slate-50 dark:bg-slate-900/30">
                        {messages.map(m => (
                            <div key={m.id} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in-up-short`}>
                                <div className={`max-w-[85%] p-4 rounded-3xl text-xs font-bold leading-relaxed shadow-sm ${
