            const nameEN = normalize(c.name.common);
            const officialPT = normalize(c.translations?.por?.official || "");
            const code = c.cca3.toLowerCase();
            const capitals = (c.capital || []).map(cap => normalize(cap));

            if (q === code) score += 100; // Match exato de código
            if (q === namePT || q === nameEN) score += 90; // Match exato de nome
            if (capitals.includes(q)) score += 80; // Match exato de capital
            if (namePT.includes(q) || nameEN.includes(q)) score += 40; // Match parcial
            if (officialPT.includes(q)) score += 30;

            return { country: c, score };
        });

        const best = results.sort((a, b) => b.score - a.score)[0];
        return (best && best.score > 10) ? best : null;
    };

    const handleSendMessage = (text: string) => {
        const query = normalize(text);
        let response = "";
        let found: Country | undefined = undefined;
        let action: (() => void) | null = null;

        // 1. Detectar Intenção de Navegação
        if (query.includes('quiz') || query.includes('jogo') || query.includes('desafio')) {
            response = language === 'pt' ? "Preparando o campo! Vamos para o Quiz." : "Preparing the field! Let's go to the Quiz.";
            action = () => onNavigate('quiz');
        } 
        else if (query.includes('designer') || query.includes('criar') || query.includes('fazer')) {
