            action = () => onNavigate('designer');
        }
        else if (query.includes('descobrir') || query.includes('discover') || query.includes('colecao')) {
            response = language === 'pt' ? "Abrindo as coleções curadas na seção Descobrir." : "Opening curated collections in the Discover section.";
            action = () => onNavigate('discover');
        }

        // 2. Detectar Intenção Estatística
        else if (query.includes('maior populacao') || query.includes('mais populoso')) {
            found = [...countries].sort((a, b) => b.population - a.population)[0];
            response = language === 'pt' 
                ? `O país mais populoso do mundo é ${getCountryDisplayName(found)}, com mais de ${found.population.toLocaleString('pt-BR')} habitantes!`
                : `The most populous country in the world is ${getCountryDisplayName(found)}, with over ${found.population.toLocaleString('en-US')} people!`;
        }
        else if (query.includes('maior pais') || query.includes('maior area')) {
            found = [...countries].sort((a, b) => b.area - a.area)[0];
            response = language === 'pt'
                ? `${getCountryDisplayName(found)} é o maior país em território, cobrindo ${found.area.toLocaleString('pt-BR')} km².`
                : `${getCountryDisplayName(found)} is the largest country by territory, covering ${found.area.toLocaleString('en-US')} km².`;
