                found = matchResult.country;
                const descKey = `${found.name.common.toLowerCase().replace(/\s/g, '')}FlagDesc`;
                const fact = t(descKey);
                response = (fact && fact !== descKey) ? fact : (language === 'pt' ? `A bandeira de ${getCountryDisplayName(found)} tem uma história incrível ligada à sua região!` : `The flag of ${getCountryDisplayName(found)} has an incredible history linked to its region!`);
            } else {
                try {
                    const facts = JSON.parse(t('flagFactsList'));
                    response = facts[Math.floor(Math.random() * facts.length)].replace(/\*\*/g, "");
                } catch (e) {
                    response = language === 'pt' ? "Você sabia que a bandeira do Nepal é a única no mundo que não é retangular?" : "Did you know that Nepal's flag is the only one in the world that is not rectangular?";
                }
            }
        }

        // 4. Busca Padrão de País
        else {
            const matchResult = findBestMatch(text);
            if (matchResult) {
                found = matchResult.country;
                response = language === 'pt' 
                    ? `Encontrei! ${getCountryDisplayName(found)} (Capital: ${found.capital?.[0] || 'N/A'}). Estou abrindo os detalhes para você.` 
                    : `Found it! ${getCountryDisplayName(found)} (Capital: ${found.capital?.[0] || 'N/A'}). Opening details for you.`;
                action = () => onSelectCountry(found!);
            } else {
                response = language === 'pt' 
                    ? "Não consegui identificar o país. Tente digitar apenas o nome, como 'Japão' ou 'Itália'." 
                    : "I couldn't identify the country. Try typing just the name, like 'Japan' or 'Italy'.";
            }
        }

        const vexyMsg: Message = {
            id: Date.now(),
            text: response,
            sender: 'vexy',
            timestamp: new Date(),
            foundCountry: found
        };

        setMessages(prev => [...prev, vexyMsg]);
        if (action) setTimeout(action, 2000);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        const currentInput = input;
        setInput('');
        setIsTyping(true);

        setTimeout(() => {
            handleSendMessage(currentInput);
            setIsTyping(false);
        }, 800);
    };

    return (
        <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
