                                    <div className={`text-[8px] mt-2 opacity-50 font-black ${m.sender === 'user' ? 'text-right' : 'text-left'}`}>
                                        {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
