    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const [lastContextCountry, setLastContextCountry] = useState<Country | null>(null);
    const [messages, setMessages] = useState<Message[]>([
        {
            id: 1,
            text: language === 'pt' 
                ? 'Olá! Sou o Vexy. Sou especialista em bandeiras e posso te contar curiosidades, mostrar mapas ou ajudar a encontrar qualquer país. O que deseja saber?' 
                : 'Hi! I am Vexy. I am a flag specialist and I can tell you curiosities, show maps, or help find any country. What do you want to know?',
            sender: 'vexy',
            timestamp: new Date()
        }
    ]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen, isTyping]);

    const getCountryDisplayName = useCallback((c: Country) => {
        return language === 'pt' ? (c.translations?.por?.common || c.name.common) : c.name.common;
    }, [language]);

    const findBestMatch = (query: string): Country | null => {
        const q = normalize(query);
        if (q.length < 2) return null;

        const results = countries.map(c => {
            let score = 0;
            const namePT = normalize(c.translations?.por?.common || "");
            const nameEN = normalize(c.name.common);
            const code = c.cca3.toLowerCase();
            const capital = normalize(c.capital?.[0] || "");

            if (q === code) score += 100;
            if (q === namePT || q === nameEN) score += 95;
            if (q === capital) score += 80;
            if (namePT.includes(q) || nameEN.includes(q)) score += 40;

            return { country: c, score };
        });

        const best = results.sort((a, b) => b.score - a.score)[0];
        return (best && best.score > 15) ? best.country : null;
    };

    const handleSendMessage = (text: string) => {
        const query = normalize(text);
        let response = "";
        let found: Country | null = findBestMatch(text);
        let action: (() => void) | null = null;

        // Se não encontrou país na frase, verifica se o usuário está falando do contexto anterior (ele/dele/aquela)
        const contextKeywords = ['ele', 'dele', 'ela', 'nela', 'aquela', 'it', 'him', 'her', 'there'];
        const isContextual = contextKeywords.some(k => query.split(' ').includes(k));
        const effectiveCountry = found || (isContextual ? lastContextCountry : null);

        // Detecção de Intenções
        const intent = {
            isCapital: query.includes('capital'),
            isPopulation: query.includes('populacao') || query.includes('habitantes') || query.includes('gente') || query.includes('population'),
            isArea: query.includes('tamanho') || query.includes('area') || query.includes('grande') || query.includes('size'),
            isMap: query.includes('mapa') || query.includes('onde fica') || query.includes('map'),
            isHistory: query.includes('historia') || query.includes('significado') || query.includes('fato') || query.includes('history') || query.includes('curiosidade'),
            isNavigation: query.includes('quiz') || query.includes('jogo') || query.includes('designer') || query.includes('criar')
        };

        if (intent.isNavigation) {
            if (query.includes('quiz')) {
                response = language === 'pt' ? "Entendido! Vamos testar seus conhecimentos no Quiz." : "Got it! Let's test your knowledge in the Quiz.";
                action = () => onNavigate('quiz');
            } else {
                response = language === 'pt' ? "Vou te levar para o Designer de Bandeiras agora!" : "I'm taking you to the Flag Designer now!";
                action = () => onNavigate('designer');
            }
        } else if (effectiveCountry) {
            const name = getCountryDisplayName(effectiveCountry);
            setLastContextCountry(effectiveCountry);

            if (intent.isCapital) {
                response = language === 'pt' 
                    ? `A capital de ${name} é ${effectiveCountry.capital?.[0] || 'não registrada'}.` 
                    : `The capital of ${name} is ${effectiveCountry.capital?.[0] || 'not recorded'}.`;
            } else if (intent.isPopulation) {
                response = language === 'pt'
                    ? `${name} possui uma população de aproximadamente ${effectiveCountry.population.toLocaleString('pt-BR')} pessoas.`
                    : `${name} has a population of approximately ${effectiveCountry.population.toLocaleString('en-US')} people.`;
            } else if (intent.isArea) {
                response = language === 'pt'
                    ? `${name} ocupa uma área de ${effectiveCountry.area.toLocaleString('pt-BR')} km².`
                    : `${name} covers an area of ${effectiveCountry.area.toLocaleString('en-US')} km².`;
            } else if (intent.isHistory || intent.isHistory) {
                const descKey = `${effectiveCountry.name.common.toLowerCase().replace(/\s/g, '')}FlagDesc`;
                const fact = t(descKey);
                response = (fact && fact !== descKey) ? fact : (language === 'pt' ? `A bandeira de ${name} carrega as cores e a herança da sua região.` : `The flag of ${name} carries the colors and heritage of its region.`);
            } else if (intent.isMap) {
                response = language === 'pt' ? `Localizando ${name} no mapa global...` : `Locating ${name} on the global map...`;
                action = () => window.open(effectiveCountry.maps.googleMaps, '_blank');
            } else {
                response = language === 'pt'
                    ? `Aqui estão as informações de ${name}. Deseja ver os detalhes completos?`
                    : `Here is the information for ${name}. Would you like to see the full details?`;
                action = () => onSelectCountry(effectiveCountry);
            }
            found = effectiveCountry;
        } else {
            // Fatos Aleatórios se nada for encontrado
            try {
                const facts = JSON.parse(t('flagFactsList'));
                const randomFact = facts[Math.floor(Math.random() * facts.length)].replace(/\*\*/g, "");
                response = (language === 'pt' ? "Não entendi bem o país, mas você sabia? " : "Not sure about the country, but did you know? ") + randomFact;
            } catch (e) {
                response = language === 'pt' 
                    ? "Não consegui encontrar esse país. Tente digitar o nome dele ou de uma capital!" 
                    : "I couldn't find that country. Try typing its name or a capital!";
            }
        }

        const vexyMsg: Message = {
            id: Date.now(),
            text: response,
            sender: 'vexy',
            timestamp: new Date(),
            foundCountry: found || undefined
        };

        setMessages(prev => [...prev, vexyMsg]);
        if (action) setTimeout(action, 2200);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        const currentInput = input;
        setInput('');
        setIsTyping(true);

        setTimeout(() => {
            handleSendMessage(currentInput);
            setIsTyping(false);
        }, 800);
    };

    return (
        <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
                <div className="w-[340px] sm:w-[420px] h-[600px] bg-white dark:bg-slate-950 border-2 border-blue-500/20 rounded-[3rem] shadow-[0_40px_120px_rgba(0,0,0,0.5)] flex flex-col overflow-hidden animate-fade-in-up pointer-events-auto mb-4 backdrop-blur-3xl">
                    {/* Header Premium */}
                    <div className="p-7 bg-gradient-to-br from-slate-900 via-blue-900 to-indigo-950 flex justify-between items-center relative overflow-hidden border-b border-white/10">
                        <div className="absolute inset-0 opacity-20 pointer-events-none">
                            <svg width="100%" height="100%"><pattern id="grid-chat" width="24" height="24" patternUnits="userSpaceOnUse"><path d="M 24 0 L 0 0 0 24" fill="none" stroke="white" strokeWidth="0.5"/></pattern><rect width="100%" height="100%" fill="url(#grid-chat)"/></svg>
                        </div>
                        <div className="flex items-center gap-4 relative z-10">
                            <div className="w-14 h-14 bg-blue-600/30 backdrop-blur-xl rounded-2xl flex items-center justify-center text-3xl animate-float border border-white/20 shadow-inner">🤖</div>
                            <div>
                                <h3 className="text-white font-black text-lg tracking-tight leading-none mb-1">Vexy Assistant</h3>
                                <div className="flex items-center gap-2">
                                    <span className="w-2.5 h-2.5 bg-green-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(74,222,128,0.5)]"></span>
                                    <span className="text-blue-200 text-[10px] font-black uppercase tracking-[0.25em]">Online Local</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="relative z-10 p-2.5 text-white/40 hover:text-white hover:bg-white/10 rounded-2xl transition-all active:scale-90">
                            <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>

                    {/* Chat Area */}
                    <div className="flex-grow overflow-y-auto p-6 space-y-6 no-scrollbar bg-slate-50 dark:bg-slate-900/40">
                        {messages.map(m => (
                            <div key={m.id} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in-up-short`}>
                                <div className={`relative max-w-[88%] p-5 rounded-[2rem] text-sm font-bold leading-relaxed shadow-xl ${
                                    m.sender === 'user' 
                                        ? 'bg-blue-600 text-white rounded-tr-none' 
                                        : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 rounded-tl-none border border-slate-200/50 dark:border-slate-700'
                                }`}>
                                    {m.text}

                                    {m.foundCountry && m.sender === 'vexy' && (
                                        <div className="mt-5 p-1 bg-slate-100 dark:bg-slate-950 rounded-[1.8rem] overflow-hidden border border-black/5 dark:border-white/5 group shadow-inner">
                                            <div className="relative aspect-[16/9] rounded-[1.5rem] overflow-hidden">
                                                <img src={m.foundCountry.flags.svg} alt="" className="w-full h-full object-cover" />
                                                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent"></div>
                                                <div className="absolute bottom-3 left-4 flex items-center gap-2">
                                                     <span className="px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-[9px] font-black text-white uppercase tracking-widest">
                                                         {m.foundCountry.cca3}
                                                     </span>
                                                </div>
                                            </div>
                                            <div className="p-3 flex gap-2">
                                                <button 
                                                    onClick={() => onSelectCountry(m.foundCountry!)}
                                                    className="flex-1 py-2.5 bg-blue-600 text-white text-[10px] font-black rounded-xl hover:bg-blue-700 transition-all active:scale-95 uppercase tracking-widest"
                                                >
                                                    {t('discoverTitle')}
                                                </button>
                                                <a 
                                                    href={m.foundCountry.maps.googleMaps}
                                                    target="_blank"
                                                    className="p-2.5 bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-xl hover:text-blue-500 transition-all"
                                                >
                                                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" /></svg>
                                                </a>
                                            </div>
                                        </div>
                                    )}

                                    <div className={`text-[9px] mt-3 opacity-40 font-black ${m.sender === 'user' ? 'text-right' : 'text-left'}`}>
                                        {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </div>
                                </div>
                            </div>
                        ))}
                        {isTyping && (
                            <div className="flex justify-start animate-fade-in-up-short">
                                <div className="bg-white dark:bg-slate-800 p-5 rounded-[2rem] rounded-tl-none shadow-lg flex gap-1.5 border border-slate-200/50 dark:border-slate-700">
