                                    <span className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                                    <span className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Input Area */}
                    <form onSubmit={handleSubmit} className="p-6 bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 flex gap-3 items-center">
                        <div className="relative flex-grow">
                             <input 
                                type="text"
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                placeholder={language === 'pt' ? "Pergunte algo ao Vexy..." : "Ask Vexy something..."}
                                className="w-full bg-slate-100 dark:bg-slate-900 border-2 border-transparent focus:border-blue-500 rounded-[1.5rem] px-6 py-4 text-sm font-bold outline-none dark:text-white transition-all shadow-inner"
                            />
                        </div>
                        <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 transition-all shadow-[0_10px_20px_rgba(37,99,235,0.3)] active:scale-90 flex-shrink-0">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
                        </button>
                    </form>
                </div>
            )}

            {/* Float Button */}
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className="w-24 h-24 bg-blue-600 rounded-[2.5rem] shadow-[0_20px_50px_rgba(37,99,235,0.4)] flex items-center justify-center text-5xl pointer-events-auto hover:scale-110 active:scale-90 transition-all border-4 border-white dark:border-slate-800 group relative overflow-hidden"
            >
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent skew-x-[-25deg] animate-metal-shimmer"></div>
                {isOpen ? '✕' : '🤖'}
            </button>
        </div>
    );
};

export default VexyChatbot;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useLanguage } from '../context/LanguageContext';
import type { Country } from '../types';

interface Message {
    id: number;
    text: string;
    sender: 'user' | 'vexy';
    timestamp: Date;
    foundCountry?: Country;
}

interface VexyChatbotProps {
    countries: Country[];
    onNavigate: (view: any) => void;
    onSelectCountry: (country: Country) => void;
}

// Utilitário para normalizar strings para busca (remove acentos e espaços)
const normalize = (str: string) => str.toLowerCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

const VexyChatbot: React.FC<VexyChatbotProps> = ({ countries, onNavigate, onSelectCountry }) => {
    const { t, language } = useLanguage();
    const [isOpen, setIsOpen] = useState(false);
    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const [lastContextCountry, setLastContextCountry] = useState<Country | null>(null);
    const [messages, setMessages] = useState<Message[]>([
        {
            id: 1,
            text: language === 'pt' 
                ? 'Olá! Sou o Vexy, sua inteligência especializada em bandeiras. Posso te contar histórias, encontrar países ou te levar para os jogos. O que vamos explorar hoje?' 
                : 'Hi! I am Vexy, your flag-specialized intelligence. I can tell you stories, find countries, or take you to the games. What shall we explore today?',
            sender: 'vexy',
            timestamp: new Date()
        }
    ]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen, isTyping]);

    const getCountryDisplayName = useCallback((c: Country) => {
        return language === 'pt' ? (c.translations?.por?.common || c.name.common) : c.name.common;
    }, [language]);

    // Motor de Busca Heurístico (Simula IA)
    const processQuery = (text: string) => {
        const q = normalize(text);
        let response = "";
        let foundCountry: Country | null = null;
        let action: (() => void) | null = null;

        // 1. Detecção de Intenção de Navegação
        if (q.includes('quiz') || q.includes('jogo') || q.includes('desafio')) {
            response = language === 'pt' ? "Preparando o campo! Vamos para o Quiz Vexilológico." : "Field ready! Let's go to the Vexillology Quiz.";
            action = () => onNavigate('quiz');
        } 
        else if (q.includes('designer') || q.includes('criar') || q.includes('fazer')) {
            response = language === 'pt' ? "Oficina aberta! Vamos criar sua bandeira no Designer." : "Workshop open! Let's create your flag in the Designer.";
            action = () => onNavigate('designer');
        }

        // 2. Busca por país (com suporte a contexto: "dele", "ela", "ele")
        const contextKeywords = ['ele', 'dele', 'ela', 'nela', 'aquela', 'it', 'him', 'her'];
        const isContextual = contextKeywords.some(k => q.split(' ').includes(k));

        // Tentar encontrar um novo país na frase
        const potentialCountry = countries.find(c => {
            const namePT = normalize(c.translations?.por?.common || "");
            const nameEN = normalize(c.name.common);
            const code = c.cca3.toLowerCase();
            const capital = normalize(c.capital?.[0] || "");
            return q.includes(namePT) || q.includes(nameEN) || q.includes(code) || (q.includes(capital) && capital.length > 3);
        });

        const activeCountry = potentialCountry || (isContextual ? lastContextCountry : null);

        if (activeCountry) {
            setLastContextCountry(activeCountry);
            foundCountry = activeCountry;
            const name = getCountryDisplayName(activeCountry);

            // Detecção de Intenção de Informação
            if (q.includes('capital')) {
                response = language === 'pt' 
                    ? `A capital de ${name} é ${activeCountry.capital?.[0] || 'não informada'}.` 
                    : `The capital of ${name} is ${activeCountry.capital?.[0] || 'N/A'}.`;
            } else if (q.includes('populacao') || q.includes('gente') || q.includes('habitantes')) {
                response = language === 'pt'
                    ? `${name} tem uma população de aproximadamente ${activeCountry.population.toLocaleString('pt-BR')} pessoas.`
                    : `${name} has a population of approximately ${activeCountry.population.toLocaleString('en-US')} people.`;
            } else if (q.includes('area') || q.includes('tamanho')) {
                response = language === 'pt'
                    ? `${name} ocupa um território de ${activeCountry.area.toLocaleString('pt-BR')} km².`
                    : `${name} covers an area of ${activeCountry.area.toLocaleString('en-US')} km².`;
            } else if (q.includes('historia') || q.includes('significado') || q.includes('curiosidade')) {
                const descKey = `${activeCountry.name.common.toLowerCase().replace(/\s/g, '')}FlagDesc`;
                const fact = t(descKey);
                response = (fact && fact !== descKey) ? fact : (language === 'pt' ? `A bandeira de ${name} é rica em simbolismo regional.` : `The flag of ${name} is rich in regional symbolism.`);
            } else {
                response = language === 'pt'
                    ? `Encontrei ${name}! Deseja ver os detalhes completos ou ver no mapa?`
                    : `Found ${name}! Do you want to see full details or view on map?`;
                action = () => onSelectCountry(activeCountry);
            }
        } 

        // 3. Fatos aleatórios se nada for detectado
        if (!response) {
            if (q.includes('fato') || q.includes('curiosidade')) {
                try {
                    const facts = JSON.parse(t('flagFactsList'));
                    response = facts[Math.floor(Math.random() * facts.length)].replace(/\*\*/g, "");
                } catch (e) {
                    response = language === 'pt' ? "Você sabia que a bandeira do Nepal é a única não retangular do mundo?" : "Did you know Nepal's flag is the only non-rectangular one in the world?";
                }
            } else {
                response = language === 'pt'
                    ? "Desculpe, não entendi. Você pode perguntar sobre a capital de um país, pedir um fato curioso ou me pedir para ir ao Quiz!"
                    : "Sorry, I didn't get that. You can ask about a country's capital, ask for a fun fact, or tell me to go to the Quiz!";
            }
        }

        const vexyMsg: Message = {
            id: Date.now(),
            text: response,
            sender: 'vexy',
            timestamp: new Date(),
            foundCountry: foundCountry || undefined
        };

        setMessages(prev => [...prev, vexyMsg]);
        if (action && !q.includes('capital') && !q.includes('populacao')) {
            setTimeout(action, 2000);
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        const currentInput = input;
        setInput('');
        setIsTyping(true);

        setTimeout(() => {
            processQuery(currentInput);
            setIsTyping(false);
        }, 1000);
    };

    return (
        <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
                <div className="w-[320px] sm:w-[420px] h-[600px] bg-white dark:bg-slate-950 border-2 border-blue-500/20 rounded-[3rem] shadow-[0_40px_100px_rgba(0,0,0,0.4)] flex flex-col overflow-hidden animate-fade-in-up pointer-events-auto mb-4 backdrop-blur-3xl">
                    {/* Premium Header */}
                    <div className="p-7 bg-gradient-to-br from-blue-700 via-blue-800 to-indigo-950 flex justify-between items-center relative overflow-hidden border-b border-white/10">
                        <div className="absolute inset-0 opacity-10 pointer-events-none">
                            <svg width="100%" height="100%"><pattern id="grid-vexy" width="20" height="20" patternUnits="userSpaceOnUse"><path d="M 20 0 L 0 0 0 20" fill="none" stroke="white" strokeWidth="0.5"/></pattern><rect width="100%" height="100%" fill="url(#grid-vexy)"/></svg>
                        </div>
                        <div className="flex items-center gap-4 relative z-10">
                            <div className="w-14 h-14 bg-white/10 backdrop-blur-xl rounded-2xl flex items-center justify-center text-3xl animate-float border border-white/20 shadow-inner">🤖</div>
                            <div>
                                <h3 className="text-white font-black text-lg tracking-tight leading-none mb-1">Vexy Assistant</h3>
                                <div className="flex items-center gap-2">
                                    <span className="w-2.5 h-2.5 bg-green-400 rounded-full animate-pulse"></span>
                                    <span className="text-blue-100 text-[10px] font-black uppercase tracking-[0.2em]">IA Local Ativa</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="relative z-10 p-2 text-white/40 hover:text-white hover:bg-white/10 rounded-xl transition-all">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>

                    {/* Chat Messages */}
                    <div className="flex-grow overflow-y-auto p-6 space-y-6 no-scrollbar bg-slate-50 dark:bg-slate-900/30">
                        {messages.map(m => (
                            <div key={m.id} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in-up-short`}>
                                <div className={`relative max-w-[85%] p-5 rounded-[2rem] text-sm font-bold leading-relaxed shadow-xl ${
                                    m.sender === 'user' 
                                        ? 'bg-blue-600 text-white rounded-tr-none' 
                                        : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 rounded-tl-none border border-slate-200/50 dark:border-slate-700'
                                }`}>
                                    {m.text}

                                    {m.foundCountry && m.sender === 'vexy' && (
                                        <div className="mt-5 p-1 bg-slate-100 dark:bg-slate-900/50 rounded-3xl border border-black/5 dark:border-white/5 overflow-hidden group">
                                            <div className="relative aspect-video rounded-2xl overflow-hidden shadow-inner bg-black/5">
                                                <img 
