export default VexyChatbot;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useLanguage } from '../context/LanguageContext';
import type { Country } from '../types';

interface Message {
    id: number;
    text: string;
    sender: 'user' | 'vexy';
    timestamp: Date;
    foundCountry?: Country;
}

interface VexyChatbotProps {
    countries: Country[];
    onNavigate: (view: any) => void;
    onSelectCountry: (country: Country) => void;
}

// Utilitário para normalizar e limpar strings para busca semântica
const normalize = (str: string) => str.toLowerCase().trim().normalize("NFD").replace(/[\u0300//u036f]/g, "").replace(/[^a-z0-9\s]/g, "");

const VexyChatbot: React.FC<VexyChatbotProps> = ({ countries, onNavigate, onSelectCountry }) => {
    const { t, language } = useLanguage();
    const [isOpen, setIsOpen] = useState(false);
    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const [lastContextCountry, setLastContextCountry] = useState<Country | null>(null);
    const [messages, setMessages] = useState<Message[]>([
        {
            id: 1,
            text: language === 'pt' 
                ? 'Olá! Sou o Vexy, seu guia oficial. Posso encontrar bandeiras, contar histórias sobre cores, calcular estatísticas mundiais ou te levar para os jogos. O que vamos explorar?' 
                : 'Hi! I am Vexy, your official guide. I can find flags, tell stories about colors, calculate world stats, or take you to the games. What shall we explore?',
            sender: 'vexy',
            timestamp: new Date()
        }
    ]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen, isTyping]);

    const getCountryDisplayName = useCallback((c: Country) => {
        return language === 'pt' ? (c.translations?.por?.common || c.name.common) : c.name.common;
    }, [language]);

    // Motor de Busca com Scoring (Simula IA de NLP)
    const findBestMatch = (query: string): Country | null => {
        const q = normalize(query);
        if (q.length < 2) return null;

        const results = countries.map(c => {
            let score = 0;
            const namePT = normalize(c.translations?.por?.common || "");
            const nameEN = normalize(c.name.common);
            const code = c.cca3.toLowerCase();
            const capital = normalize(c.capital?.[0] || "");

            if (q === code) score += 100; // Match exato de código
            if (q === namePT || q === nameEN) score += 95; // Match exato de nome
            if (q === capital) score += 80; // Match de capital
            if (namePT.includes(q) || nameEN.includes(q)) score += 40; // Parcial

            return { country: c, score };
        });

        const best = results.sort((a, b) => b.score - a.score)[0];
        return (best && best.score > 15) ? best.country : null;
    };

    const processQuery = (text: string) => {
        const q = normalize(text);
        let response = "";
        let found: Country | null = findBestMatch(text);
        let action: (() => void) | null = null;

        // 1. Detecção de Navegação
        if (q.includes('quiz') || q.includes('jogo') || q.includes('desafio')) {
            response = language === 'pt' ? "Preparando o campo! Vamos para o Quiz." : "Preparing the field! Let's go to the Quiz.";
            action = () => onNavigate('quiz');
        } 
        else if (q.includes('designer') || q.includes('criar') || q.includes('fazer')) {
            response = language === 'pt' ? "Oficina aberta! Vamos criar sua bandeira no Designer." : "Workshop open! Let's create your flag in the Designer.";
            action = () => onNavigate('designer');
        }

        // 2. Lógica Estatística (Maior/Menor/Populoso)
        else if (q.includes('maior pais') || q.includes('maior area')) {
            found = [...countries].sort((a, b) => b.area - a.area)[0];
            response = language === 'pt' 
