                : `${getCountryDisplayName(found)} is the world's largest country by area, with ${found.area.toLocaleString('en-US')} km²!`;
        }
        else if (q.includes('mais populoso') || q.includes('maior populacao') || q.includes('mais gente')) {
            found = [...countries].sort((a, b) => b.population - a.population)[0];
            response = language === 'pt'
                ? `O gigante populacional é ${getCountryDisplayName(found)}, com mais de ${found.population.toLocaleString('pt-BR')} habitantes.`
                : `The population giant is ${getCountryDisplayName(found)}, with over ${found.population.toLocaleString('en-US')} inhabitants.`;
        }

        // 3. Suporte a Contexto (Pronominal)
        const contextKeywords = ['ele', 'dele', 'ela', 'nela', 'aquela', 'it', 'him', 'her', 'there'];
        const isContextual = contextKeywords.some(k => q.split(/\s+/).includes(k));
        const effectiveCountry = found || (isContextual ? lastContextCountry : null);

        if (effectiveCountry) {
            setLastContextCountry(effectiveCountry);
            const name = getCountryDisplayName(effectiveCountry);
            found = effectiveCountry;

            if (q.includes('capital')) {
                response = language === 'pt' 
                    ? `A capital de ${name} é ${effectiveCountry.capital?.[0] || 'não registrada'}.` 
                    : `The capital of ${name} is ${effectiveCountry.capital?.[0] || 'not recorded'}.`;
            } else if (q.includes('populacao') || q.includes('gente')) {
                response = language === 'pt'
                    ? `${name} tem ${effectiveCountry.population.toLocaleString('pt-BR')} habitantes.`
                    : `${name} has ${effectiveCountry.population.toLocaleString('en-US')} inhabitants.`;
            } else if (q.includes('historia') || q.includes('significado') || q.includes('curiosidade') || q.includes('fato')) {
                const descKey = `${effectiveCountry.name.common.toLowerCase().replace(/\s/g, '')}FlagDesc`;
                const fact = t(descKey);
                response = (fact && fact !== descKey) ? fact : (language === 'pt' ? `A bandeira de ${name} tem um design único que reflete sua cultura regional.` : `The flag of ${name} has a unique design reflecting its regional culture.`);
            } else if (q.includes('mapa')) {
                response = language === 'pt' ? `Localizando ${name} no mapa global...` : `Locating ${name} on the global map...`;
                action = () => window.open(effectiveCountry.maps.googleMaps, '_blank');
            } else if (!response) {
                response = language === 'pt' ? `Encontrei informações sobre ${name}. Quer ver os detalhes?` : `I found information about ${name}. Want to see details?`;
                action = () => onSelectCountry(effectiveCountry);
            }
        }

        // 4. Fallback "IA Generativa Local" (Fatos Aleatórios)
        if (!response) {
            if (q.includes('quem') && q.includes('voce')) {
                response = language === 'pt' ? "Eu sou o Vexy, uma inteligência local criada para ser sua enciclopédia viva sobre bandeiras e nações!" : "I am Vexy, a local intelligence created to be your living encyclopedia of flags and nations!";
            } else {
                try {
                    const facts = JSON.parse(t('flagFactsList'));
                    const randomFact = facts[Math.floor(Math.random() * facts.length)].replace(/\*\*/g, "");
                    response = (language === 'pt' ? "Não identifiquei o país, mas aqui vai uma curiosidade: " : "Couldn't pinpoint the country, but here's a fun fact: ") + randomFact;
                } catch (e) {
                    response = language === 'pt' ? "Desculpe, não entendi. Tente perguntar sobre um país específico, como 'Qual a capital da França?'" : "Sorry, I didn't get that. Try asking about a specific country, like 'What is the capital of France?'";
                }
            }
        }

        const vexyMsg: Message = {
            id: Date.now(),
            text: response,
            sender: 'vexy',
            timestamp: new Date(),
            foundCountry: found || undefined
        };

        setMessages(prev => [...prev, vexyMsg]);
        if (action && !q.includes('capital') && !q.includes('populacao')) {
            setTimeout(action, 2000);
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        const currentInput = input;
        setInput('');
        setIsTyping(true);

        setTimeout(() => {
            processQuery(currentInput);
            setIsTyping(false);
        }, 800);
    };

    return (
        <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
                <div className="w-[320px] sm:w-[420px] h-[600px] bg-white/95 dark:bg-slate-950/95 border-2 border-blue-500/20 rounded-[3rem] shadow-[0_40px_100px_rgba(0,0,0,0.4)] flex flex-col overflow-hidden animate-fade-in-up pointer-events-auto mb-4 backdrop-blur-3xl">
                    {/* Premium Header */}
                    <div className="p-7 bg-gradient-to-br from-slate-900 via-blue-900 to-indigo-950 flex justify-between items-center relative overflow-hidden border-b border-white/10">
                        <div className="absolute inset-0 opacity-10 pointer-events-none">
                            <svg width="100%" height="100%"><pattern id="grid-vexy" width="24" height="24" patternUnits="userSpaceOnUse"><path d="M 24 0 L 0 0 0 24" fill="none" stroke="white" strokeWidth="0.5"/></pattern><rect width="100%" height="100%" fill="url(#grid-vexy)"/></svg>
                        </div>
                        <div className="flex items-center gap-4 relative z-10">
                            <div className="w-14 h-14 bg-blue-600/30 backdrop-blur-xl rounded-2xl flex items-center justify-center text-3xl animate-float border border-white/20 shadow-inner">🤖</div>
                            <div>
                                <h3 className="text-white font-black text-lg tracking-tight leading-none mb-1">Vexy Intelligence</h3>
                                <div className="flex items-center gap-2">
                                    <span className="w-2.5 h-2.5 bg-green-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(74,222,128,0.5)]"></span>
                                    <span className="text-blue-100 text-[10px] font-black uppercase tracking-[0.2em]">Cérebro Local Ativo</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="relative z-10 p-2.5 text-white/40 hover:text-white hover:bg-white/10 rounded-2xl transition-all active:scale-90">
                            <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
