    const [messages, setMessages] = useState<Message[]>([]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Inicialização da Saudação
    useEffect(() => {
        if (messages.length === 0) {
            setMessages([{
                id: 1,
                text: language === 'pt' 
                    ? 'Olá! Sou o Vexy Pro. Posso te contar o significado secreto das cores, comparar nações ou te desafiar no Quiz. Sobre qual país quer saber agora?' 
                    : 'Hello! I am Vexy Pro. I can tell you the secret meaning of colors, compare nations, or challenge you in the Quiz. Which country do you want to know about?',
                sender: 'vexy',
                timestamp: new Date(),
                suggestions: language === 'pt' ? ['Brasil 🇧🇷', 'Japão 🇯🇵', 'Fato Curioso 💡'] : ['USA 🇺🇸', 'Japan 🇯🇵', 'Random Fact 💡']
            }]);
        }
    }, [language, messages.length]);

